1	import { useState, useEffect } from "react";
2	import {
3	  snapshotsApi,
4	  type RestorePreview,
5	  type RestorePreviewRow,
6	  type RestoreRequest,
7	} from "../../api/bulkUpdate";
8	import { showToast } from "../../shared/components/Toast";
9	
10	// ---------------------------------------------------------------------------
11	// Shared styles (local copies — only what this modal needs)
12	// ---------------------------------------------------------------------------
13	
14	const BTN_PRIMARY: React.CSSProperties = {
15	  padding: "6px 16px",
16	  borderRadius: "6px",
17	  border: "none",
18	  background: "var(--io-accent)",
19	  color: "var(--io-text-on-accent)",
20	  fontWeight: 600,
21	  fontSize: "13px",
22	  cursor: "pointer",
23	};
24	
25	const BTN_SECONDARY: React.CSSProperties = {
26	  padding: "6px 16px",
27	  borderRadius: "6px",
28	  border: "1px solid var(--io-border)",
29	  background: "var(--io-surface-sunken)",
30	  color: "var(--io-text-primary)",
31	  fontWeight: 500,
32	  fontSize: "13px",
33	  cursor: "pointer",
34	};
35	
36	const TABLE: React.CSSProperties = {
37	  width: "100%",
38	  borderCollapse: "collapse" as const,
39	  fontSize: "12px",
40	};
41	
42	const TH: React.CSSProperties = {
43	  textAlign: "left" as const,
44	  padding: "6px 10px",
45	  borderBottom: "1px solid var(--io-border)",
46	  color: "var(--io-text-muted)",
47	  fontWeight: 600,
48	  background: "var(--io-surface-sunken)",
49	};
50	
51	const TD: React.CSSProperties = {
52	  padding: "6px 10px",
53	  borderBottom: "1px solid var(--io-border)",
54	  color: "var(--io-text-primary)",
55	  verticalAlign: "top" as const,
56	};
57	
58	// ---------------------------------------------------------------------------
59	// Badge — inline status pill
60	// ---------------------------------------------------------------------------
61	
62	function Badge({
63	  children,
64	  color,
65	}: {
66	  children: React.ReactNode;
67	  color: "success" | "warning" | "danger" | "accent" | "muted";
68	}) {
69	  const colors = {
70	    success: { bg: "var(--io-success-subtle)", fg: "var(--io-success)" },
71	    warning: { bg: "var(--io-warning-subtle)", fg: "var(--io-warning)" },
72	    danger: { bg: "var(--io-danger-subtle)", fg: "var(--io-danger)" },
73	    accent: { bg: "var(--io-accent-subtle)", fg: "var(--io-accent)" },
74	    muted: { bg: "var(--io-surface-sunken)", fg: "var(--io-text-muted)" },
75	  };
76	  const c = colors[color];
77	  return (
78	    <span
79	      style={{
80	        display: "inline-block",
81	        padding: "2px 8px",
82	        borderRadius: "999px",
83	        fontSize: "11px",
84	        fontWeight: 600,
85	        background: c.bg,
86	        color: c.fg,
87	      }}
88	    >
89	      {children}
90	    </span>
91	  );
92	}
93	
94	// ---------------------------------------------------------------------------
95	// RestorePreviewDiffTable — renders field-level diff rows
96	// ---------------------------------------------------------------------------
97	
98	function RestorePreviewDiffTable({
99	  rows,
100	  mode,
101	  selectedIds,
102	  onToggle,
103	}: {
104	  rows: RestorePreviewRow[];
105	  mode: "all" | "selective";
106	  selectedIds: Set<string>;
107	  onToggle: (id: string) => void;
108	}) {
109	  if (rows.length === 0) {
110	    return (
111	      <p
112	        style={{
113	          padding: "var(--io-space-4)",
114	          color: "var(--io-text-muted)",
115	          fontSize: "12px",
116	        }}
117	      >
118	        No rows in this snapshot.
119	      </p>
120	    );
121	  }
122	
123	  // Collect all unique fields across all rows for table columns
124	  const allFields = Array.from(
125	    new Set(
126	      rows.flatMap((r) =>
127	        Object.keys(r.snapshot_values).filter((k) => k !== "id"),
128	      ),
129	    ),
130	  ).slice(0, 8); // limit columns for readability
131	
132	  return (
133	    <table style={{ ...TABLE, fontSize: "11px" }}>
134	      <thead>
135	        <tr>
136	          {mode === "selective" && <th style={{ ...TH, width: 32 }}></th>}
137	          <th style={TH}>ID</th>
138	          <th style={{ ...TH, width: 80 }}>Status</th>
139	          {allFields.map((f) => (
140	            <th key={f} style={TH}>
141	              {f}
142	            </th>
143	          ))}
144	        </tr>
145	      </thead>
146	      <tbody>
147	        {rows.map((row) => {
148	          const isSelected = selectedIds.has(row.id);
149	          const hasChanges = row.changed_fields.length > 0;
150	          return (
151	            <tr
152	              key={row.id}
153	              style={{
154	                background: row.conflicted
155	                  ? "var(--io-warning-subtle)"
156	                  : isSelected && mode === "selective"
157	                    ? "var(--io-accent-subtle)"
158	                    : undefined,
159	                cursor: mode === "selective" ? "pointer" : undefined,
160	              }}
161	              onClick={() => mode === "selective" && onToggle(row.id)}
162	            >
163	              {mode === "selective" && (
164	                <td style={{ ...TD, textAlign: "center" as const }}>
165	                  <input
166	                    type="checkbox"
167	                    checked={isSelected}
168	                    onChange={() => onToggle(row.id)}
169	                    onClick={(e) => e.stopPropagation()}
170	                  />
171	                </td>
172	              )}
173	              <td
174	                style={{
175	                  ...TD,
176	                  fontFamily: "monospace",
177	                  fontSize: "10px",
178	                  color: "var(--io-text-muted)",
179	                }}
180	              >
181	                {row.id.slice(0, 8)}…
182	              </td>
183	              <td style={TD}>
184	                {row.conflicted ? (
185	                  <span
186	                    style={{
187	                      color: "var(--io-warning)",
188	                      fontWeight: 600,
189	                      fontSize: "11px",
190	                    }}
191	                  >
192	                    &#9888; Conflict
193	                  </span>
194	                ) : hasChanges ? (
195	                  <Badge color="accent">Changed</Badge>
196	                ) : (
197	                  <Badge color="muted">Same</Badge>
198	                )}
199	              </td>
200	              {allFields.map((field) => {
201	                const snapVal = row.snapshot_values[field];
202	                const currVal = row.current_values[field];
203	                const isChanged = row.changed_fields.includes(field);
204	                const snapStr =
205	                  snapVal === null || snapVal === undefined
206	                    ? "—"
207	                    : String(snapVal).replace(/^"|"$/g, "");
208	                const currStr =
209	                  currVal === null || currVal === undefined
210	                    ? "—"
211	                    : String(currVal).replace(/^"|"$/g, "");
212	                return (
213	                  <td
214	                    key={field}
215	                    style={{
216	                      ...TD,
217	                      background: isChanged
218	                        ? "var(--io-danger-subtle)"
219	                        : undefined,
220	                    }}
221	                  >
222	                    {isChanged ? (
223	                      <div
224	                        style={{
225	                          display: "flex",
226	                          flexDirection: "column",
227	                          gap: 2,
228	                        }}
229	                      >
230	                        <span
231	                          style={{
232	                            color: "var(--io-danger)",
233	                            textDecoration: "line-through",
234	                            fontSize: "10px",
235	                          }}
236	                        >
237	                          {currStr}
238	                        </span>
239	                        <span
240	                          style={{
241	                            color: "var(--io-success)",
242	                            fontSize: "10px",
243	                          }}
244	                        >
245	                          {snapStr}
246	                        </span>
247	                      </div>
248	                    ) : (
249	                      <span
250	                        style={{
251	                          color: "var(--io-text-muted)",
252	                          fontSize: "10px",
253	                        }}
254	                      >
255	                        {snapStr}
256	                      </span>
257	                    )}
258	                  </td>
259	                );
260	              })}
261	            </tr>
262	          );
263	        })}
264	      </tbody>
265	    </table>
266	  );
267	}
268	
269	// ---------------------------------------------------------------------------
270	// RestorePreviewModal — multi-step restore preview with field-level diff
271	// ---------------------------------------------------------------------------
272	
273	export function RestorePreviewModal({
274	  snapshotId,
275	  snapshotLabel,
276	  onClose,
277	  onRestored,
278	}: {
279	  snapshotId: string;
280	  snapshotLabel?: string | null;
281	  onClose: () => void;
282	  onRestored: (result: {
283	    rows_restored: number;
284	    safety_snapshot_id: string | null;
285	  }) => void;
286	}) {
287	  const [step, setStep] = useState<1 | 2 | 3>(1);
288	  const [preview, setPreview] = useState<RestorePreview | null>(null);
289	  const [loadError, setLoadError] = useState<string | null>(null);
290	  const [mode, setMode] = useState<"all" | "selective">("all");
291	  const [selectedRowIds, setSelectedRowIds] = useState<Set<string>>(new Set());
292	  const [createSafetySnapshot, setCreateSafetySnapshot] = useState(true);
293	  const [isRestoring, setIsRestoring] = useState(false);
294	
295	  // Load preview on mount
296	  useEffect(() => {
297	    snapshotsApi
298	      .restorePreview(snapshotId)
299	      .then((res) => {
300	        if (res.success) {
301	          setPreview(res.data);
302	          setStep(2);
303	        } else {
304	          setLoadError(res.error.message);
305	        }
306	      })
307	      .catch(() => {
308	        setLoadError("Network error loading restore preview");
309	      });
310	     
311	  }, [snapshotId]);
312	
313	  const toggleRow = (id: string) => {
314	    setSelectedRowIds((prev) => {
315	      const next = new Set(prev);
316	      if (next.has(id)) next.delete(id);
317	      else next.add(id);
318	      return next;
319	    });
320	  };
321	
322	  const selectAll = () => {
323	    if (preview) setSelectedRowIds(new Set(preview.rows.map((r) => r.id)));
324	  };
325	
326	  const clearAll = () => setSelectedRowIds(new Set());
327	
328	  const rowCount =
329	    mode === "all" ? (preview?.total_rows ?? 0) : selectedRowIds.size;
330	
331	  const handleRestore = async () => {
332	    setIsRestoring(true);
333	    const req: RestoreRequest = {
334	      mode,
335	      create_safety_snapshot: createSafetySnapshot,
336	      row_ids: mode === "selective" ? Array.from(selectedRowIds) : undefined,
337	    };
338	    try {
339	      const res = await snapshotsApi.restore(snapshotId, req);
340	      if (res.success) {
341	        onRestored({
342	          rows_restored: res.data.rows_restored,
343	          safety_snapshot_id: res.data.safety_snapshot_id,
344	        });
345	      } else {
346	        showToast({
347	          title: "Restore failed",
348	          description: res.error.message,
349	          variant: "error",
350	        });
351	        setIsRestoring(false);
352	      }
353	    } catch {
354	      showToast({
355	        title: "Restore failed",
356	        description: "Network error",
357	        variant: "error",
358	      });
359	      setIsRestoring(false);
360	    }
361	  };
362	
363	  const MODAL_OVERLAY: React.CSSProperties = {
364	    position: "fixed",
365	    inset: 0,
366	    background: "var(--io-modal-backdrop)",
367	    display: "flex",
368	    alignItems: "center",
369	    justifyContent: "center",
370	    zIndex: 9999,
371	  };
372	
373	  const MODAL_BOX: React.CSSProperties = {
374	    background: "var(--io-surface-primary)",
375	    border: "1px solid var(--io-border)",
376	    borderRadius: "10px",
377	    padding: "var(--io-space-6)",
378	    maxWidth: 860,
379	    width: "95%",
380	    maxHeight: "85vh",
381	    display: "flex",
382	    flexDirection: "column",
383	    gap: "var(--io-space-4)",
384	  };
385	
386	  return (
387	    <div style={MODAL_OVERLAY}>
388	      <div style={MODAL_BOX}>
389	        {/* Header */}
390	        <div
391	          style={{
392	            display: "flex",
393	            justifyContent: "space-between",
394	            alignItems: "flex-start",
395	          }}
396	        >
397	          <div>
398	            <h2
399	              style={{
400	                margin: 0,
401	                fontSize: "16px",
402	                fontWeight: 700,
403	                color: "var(--io-text-primary)",
404	              }}
405	            >
406	              Restore Snapshot
407	            </h2>
408	            {snapshotLabel && (
409	              <p
410	                style={{
411	                  margin: "2px 0 0",
412	                  fontSize: "12px",
413	                  color: "var(--io-text-muted)",
414	                }}
415	              >
416	                {snapshotLabel}
417	              </p>
418	            )}
419	          </div>
420	          <button
421	            style={{ ...BTN_SECONDARY, padding: "4px 10px", fontSize: "12px" }}
422	            onClick={onClose}
423	          >
424	            Cancel
425	          </button>
426	        </div>
427	
428	        {/* Step 1: Loading */}
429	        {step === 1 && (
430	          <div
431	            style={{
432	              padding: "var(--io-space-6)",
433	              textAlign: "center",
434	              color: "var(--io-text-muted)",
435	            }}
436	          >
437	            {loadError ? (
438	              <p style={{ color: "var(--io-danger)" }}>
439	                Failed to load restore preview: {loadError}
440	              </p>
441	            ) : (
442	              <p>Loading restore preview…</p>
443	            )}
444	          </div>
445	        )}
446	
447	        {/* Step 2: Preview & Mode Selection */}
448	        {step === 2 && preview && (
449	          <>
450	            {/* Summary bar */}
451	            <div
452	              style={{
453	                display: "flex",
454	                gap: "var(--io-space-4)",
455	                flexWrap: "wrap",
456	                fontSize: "13px",
457	              }}
458	            >
459	              <span>
460	                <strong style={{ color: "var(--io-text-primary)" }}>
461	                  {preview.total_rows}
462	                </strong>
463	                <span style={{ color: "var(--io-text-muted)", marginLeft: 4 }}>
464	                  rows in snapshot
465	                </span>
466	              </span>
467	              {preview.conflicted_count > 0 && (
468	                <span style={{ color: "var(--io-warning)", fontWeight: 600 }}>
469	                  &#9888; {preview.conflicted_count} conflicted (modified after
470	                  snapshot)
471	                </span>
472	              )}
473	              <span
474	                style={{
475	                  color: "var(--io-text-muted)",
476	                  fontFamily: "monospace",
477	                  fontSize: "11px",
478	                }}
479	              >
480	                Snapshot taken:{" "}
481	                {new Date(preview.snapshot_created_at).toLocaleString()}
482	              </span>
483	            </div>
484	
485	            {/* Mode selector */}
486	            <div
487	              style={{
488	                display: "flex",
489	                gap: "var(--io-space-4)",
490	                alignItems: "center",
491	                flexWrap: "wrap",
492	              }}
493	            >
494	              <label
495	                style={{
496	                  display: "flex",
497	                  gap: 6,
498	                  alignItems: "center",
499	                  cursor: "pointer",
500	                  fontSize: "13px",
501	                }}
502	              >
503	                <input
504	                  type="radio"
505	                  name="restore-mode"
506	                  value="all"
507	                  checked={mode === "all"}
508	                  onChange={() => setMode("all")}
509	                />
510	                Restore all {preview.total_rows} rows
511	              </label>
512	              <label
513	                style={{
514	                  display: "flex",
515	                  gap: 6,
516	                  alignItems: "center",
517	                  cursor: "pointer",
518	                  fontSize: "13px",
519	                }}
520	              >
521	                <input
522	                  type="radio"
523	                  name="restore-mode"
524	                  value="selective"
525	                  checked={mode === "selective"}
526	                  onChange={() => setMode("selective")}
527	                />
528	                Select specific rows
529	              </label>
530	              {mode === "selective" && (
531	                <div
532	                  style={{
533	                    display: "flex",
534	                    gap: "var(--io-space-2)",
535	                    marginLeft: "auto",
536	                  }}
537	                >
538	                  <button
539	                    style={{
540	                      ...BTN_SECONDARY,
541	                      fontSize: "11px",
542	                      padding: "3px 8px",
543	                    }}
544	                    onClick={selectAll}
545	                  >
546	                    Select All
547	                  </button>
548	                  <button
549	                    style={{
550	                      ...BTN_SECONDARY,
551	                      fontSize: "11px",
552	                      padding: "3px 8px",
553	                    }}
554	                    onClick={clearAll}
555	                  >
556	                    Clear
557	                  </button>
558	                </div>
559	              )}
560	            </div>
561	
562	            {/* Diff table */}
563	            <div
564	              style={{
565	                flex: 1,
566	                overflowY: "auto",
567	                overflowX: "auto",
568	                border: "1px solid var(--io-border)",
569	                borderRadius: 6,
570	              }}
571	            >
572	              <RestorePreviewDiffTable
573	                rows={preview.rows}
574	                mode={mode}
575	                selectedIds={selectedRowIds}
576	                onToggle={toggleRow}
577	              />
578	            </div>
579	
580	            {/* Safety snapshot checkbox */}
581	            <label
582	              style={{
583	                display: "flex",
584	                gap: 8,
585	                alignItems: "center",
586	                cursor: "pointer",
587	                fontSize: "13px",
588	                color: "var(--io-text-primary)",
589	              }}
590	            >
591	              <input
592	                type="checkbox"
593	                checked={createSafetySnapshot}
594	                onChange={(e) => setCreateSafetySnapshot(e.target.checked)}
595	              />
596	              Create a safety snapshot of the current state before restoring
597	            </label>
598	
599	            {/* Footer */}
600	            <div
601	              style={{
602	                display: "flex",
603	                gap: "var(--io-space-3)",
604	                justifyContent: "flex-end",
605	              }}
606	            >
607	              <button style={BTN_SECONDARY} onClick={onClose}>
608	                Cancel
609	              </button>
610	              <button
611	                style={BTN_PRIMARY}
612	                onClick={() => setStep(3)}
613	                disabled={mode === "selective" && selectedRowIds.size === 0}
614	              >
615	                Continue ({rowCount} row{rowCount !== 1 ? "s" : ""})
616	              </button>
617	            </div>
618	          </>
619	        )}
620	
621	        {/* Step 3: Final Confirmation */}
622	        {step === 3 && preview && (
623	          <>
624	            <div
625	              style={{
626	                padding: "var(--io-space-4)",
627	                background: "var(--io-warning-subtle)",
628	                borderRadius: 6,
629	                border: "1px solid var(--io-warning)",
630	                fontSize: "13px",
631	                color: "var(--io-text-primary)",
632	                lineHeight: 1.6,
633	              }}
634	            >
635	              <strong>
636	                You are about to restore {rowCount} row
637	                {rowCount !== 1 ? "s" : ""}
638	              </strong>{" "}
639	              from snapshot
640	              {snapshotLabel
641	                ? ` "${snapshotLabel}"`
642	                : ` ${snapshotId.slice(0, 8)}…`}
643	              {createSafetySnapshot && (
644	                <span>
645	                  {" "}
646	                  A safety snapshot of the current state will be created first.
647	                </span>
648	              )}
649	              {preview.conflicted_count > 0 && mode === "all" && (
650	                <div
651	                  style={{
652	                    marginTop: 6,
653	                    color: "var(--io-warning)",
654	                    fontWeight: 600,
655	                  }}
656	                >
657	                  &#9888; {preview.conflicted_count} conflicted row
658	                  {preview.conflicted_count !== 1 ? "s" : ""} will be
659	                  overwritten.
660	                </div>
661	              )}
662	            </div>
663	
664	            <div
665	              style={{
666	                display: "flex",
667	                gap: "var(--io-space-3)",
668	                justifyContent: "flex-end",
669	              }}
670	            >
671	              <button style={BTN_SECONDARY} onClick={() => setStep(2)}>
672	                Back
673	              </button>
674	              <button
675	                style={{ ...BTN_PRIMARY, background: "var(--io-danger)" }}
676	                onClick={handleRestore}
677	                disabled={isRestoring}
678	              >
679	                {isRestoring
680	                  ? "Restoring…"
681	                  : `Restore ${rowCount} Row${rowCount !== 1 ? "s" : ""}`}
682	              </button>
683	            </div>
684	          </>
685	        )}
686	      </div>
687	    </div>
688	  );
689	}
