499	// Simple in-memory custom categories store (backed by API in production)
500	function useDataCategories() {
501	  const query = useQuery<DataCategory[]>({
502	    queryKey: ["data-categories"],
503	    queryFn: async () => {
504	      try {
505	        const res = await fetch("/api/data-categories");
506	        if (!res.ok) throw new Error("API unavailable");
507	        const json = await res.json();
508	        return json.data ?? json;
509	      } catch {
510	        // Fall back to predefined only
511	        return PREDEFINED_CATEGORIES.map((c) => ({ ...c, predefined: true }));
512	      }
513	    },
514	    staleTime: 60_000,
515	    initialData: PREDEFINED_CATEGORIES.map((c) => ({ ...c, predefined: true })),
516	  });
517	  return query;
518	}
