2480	// ---------------------------------------------------------------------------
2481	// Global minimum publish interval control
2482	// ---------------------------------------------------------------------------
2483	
2484	const MIN_INTERVAL_FLOOR = 100;
2485	const MIN_INTERVAL_KEY = "opc.minimum_publish_interval_ms";
2486	const MIN_INTERVAL_DEFAULT = 1000;
2487	
2488	function MinPublishIntervalControl() {
2489	  const qc = useQueryClient();
2490	  const [localValue, setLocalValue] = useState<string>("");
2491	  const [saveStatus, setSaveStatus] = useState<"idle" | "saved" | "error">(
2492	    "idle",
2493	  );
2494	  const [saveError, setSaveError] = useState<string>("");
2495	
2496	  const settingQuery = useQuery({
2497	    queryKey: ["setting", MIN_INTERVAL_KEY],
2498	    queryFn: async () => {
2499	      const result = await settingsApi.list();
2500	      if (!result.success) return MIN_INTERVAL_DEFAULT;
2501	      const setting = (
2502	        result.data as import("../../api/settings").Setting[]
2503	      ).find((s) => s.key === MIN_INTERVAL_KEY);
2504	      return setting ? (setting.value as number) : MIN_INTERVAL_DEFAULT;
2505	    },
2506	    staleTime: 30_000,
2507	  });
2508	
2509	  React.useEffect(() => {
2510	    if (settingQuery.data != null) {
2511	      setLocalValue(String(settingQuery.data));
2512	    }
2513	  }, [settingQuery.data]);
2514	
2515	  const saveMutation = useMutation({
2516	    mutationFn: (val: number) => settingsApi.update(MIN_INTERVAL_KEY, val),
2517	    onSuccess: (result) => {
2518	      if (!result.success) {
2519	        setSaveStatus("error");
2520	        setSaveError(result.error.message);
2521	        return;
2522	      }
2523	      setSaveStatus("saved");
2524	      setSaveError("");
2525	      qc.invalidateQueries({ queryKey: ["setting", MIN_INTERVAL_KEY] });
2526	      setTimeout(() => setSaveStatus("idle"), 3000);
2527	    },
2528	    onError: (e: Error) => {
2529	      setSaveStatus("error");
2530	      setSaveError(e.message);
2531	    },
2532	  });
2533	
2534	  function handleSave() {
2535	    const parsed = parseInt(localValue, 10);
2536	    if (isNaN(parsed) || parsed < MIN_INTERVAL_FLOOR) {
2537	      setSaveStatus("error");
2538	      setSaveError(`Minimum allowed value is ${MIN_INTERVAL_FLOOR}ms`);
2539	      return;
2540	    }
2541	    setSaveStatus("idle");
2542	    setSaveError("");
2543	    saveMutation.mutate(parsed);
2544	  }
2545	
2546	  return (
2547	    <div
2548	      style={{
2549	        background: "var(--io-surface-secondary)",
2550	        border: "1px solid var(--io-border)",
2551	        borderRadius: "8px",
2552	        padding: "16px 20px",
2553	        marginBottom: "20px",
2554	      }}
2555	    >
2556	      <div
2557	        style={{
2558	          fontSize: "13px",
2559	          fontWeight: 600,
2560	          color: "var(--io-text-primary)",
2561	          marginBottom: "4px",
2562	        }}
2563	      >
2564	        Global Minimum Publish Interval
2565	      </div>
2566	      <div
2567	        style={{
2568	          fontSize: "12px",
2569	          color: "var(--io-text-muted)",
2570	          marginBottom: "12px",
2571	        }}
2572	      >
2573	        No OPC source can be configured below this floor. Protects DCS/historian
2574	        systems from aggressive polling. Default: {MIN_INTERVAL_DEFAULT}ms.
2575	        Minimum allowed: {MIN_INTERVAL_FLOOR}ms.
2576	      </div>
2577	      <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
2578	        <input
2579	          type="number"
2580	          min={MIN_INTERVAL_FLOOR}
2581	          step={100}
2582	          style={{ ...inputStyle, width: "140px" }}
2583	          value={localValue}
2584	          onChange={(e) => {
2585	            setLocalValue(e.target.value);
2586	            setSaveStatus("idle");
2587	          }}
2588	          placeholder={String(MIN_INTERVAL_DEFAULT)}
2589	        />
2590	        <span style={{ fontSize: "12px", color: "var(--io-text-muted)" }}>
2591	          ms
2592	        </span>
2593	        <button
2594	          style={btnPrimary}
2595	          type="button"
2596	          onClick={handleSave}
2597	          disabled={saveMutation.isPending}
2598	        >
2599	          {saveMutation.isPending ? "Saving…" : "Save"}
2600	        </button>
2601	        {saveStatus === "saved" && (
2602	          <span style={{ fontSize: "12px", color: "var(--io-success)" }}>
2603	            Saved
2604	          </span>
2605	        )}
2606	        {saveStatus === "error" && (
2607	          <span style={{ fontSize: "12px", color: "var(--io-danger)" }}>
2608	            {saveError}
2609	          </span>
2610	        )}
2611	      </div>
2612	    </div>
2613	  );
2614	}
