import React, { useState } from "react";
import ContextMenu from "../../shared/components/ContextMenu";
import { useContextMenu } from "../../shared/hooks/useContextMenu";
import * as Dialog from "@radix-ui/react-dialog";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import {
  pointSourcesApi,
  pointSourceStatsApi,
  historyRecoveryApi,
  PointSource,
  PointSourceStats,
  RecoveryJob,
  CreatePointSourceRequest,
  UpdatePointSourceRequest,
} from "../../api/points";
import { opcCertsApi, OpcServerCert } from "../../api/opcCerts";
import { settingsApi } from "../../api/settings";
import SupplementalConnectorsTab from "./SupplementalConnectorsTab";
import { ExportButton } from "../../shared/components/ExportDialog";
import {
  inputStyle,
  labelStyle,
  btnPrimary,
  btnSecondary,
  cellStyle,
} from "./settingsStyles";

// ---------------------------------------------------------------------------
// Column definitions for OPC sources export
// ---------------------------------------------------------------------------
const OPC_SOURCES_COLUMNS = [
  { id: "name", label: "Name" },
  { id: "endpoint_url", label: "Endpoint URL" },
  { id: "status", label: "Status" },
  { id: "enabled", label: "Enabled" },
  { id: "security_policy", label: "Security Policy" },
  { id: "security_mode", label: "Security Mode" },
  { id: "last_connected_at", label: "Last Connected" },
];

const OPC_SOURCES_DEFAULT_VISIBLE = [
  "name",
  "endpoint_url",
  "status",
  "enabled",
  "last_connected_at",
];

// ---------------------------------------------------------------------------
// TableSkeleton — shimmer rows for OPC sources table
// ---------------------------------------------------------------------------
function TableSkeleton({
  rows = 4,
  columns = 5,
}: {
  rows?: number;
  columns?: number;
}) {
  return (
    <table style={{ width: "100%", borderCollapse: "collapse" }}>
      <thead>
        <tr
          style={{
            borderBottom: "1px solid var(--io-border)",
            background: "var(--io-surface-primary)",
          }}
        >
          {Array.from({ length: columns }).map((_, i) => (
            <th key={i} style={{ padding: "10px 14px", textAlign: "left" }}>
              <div
                style={{
                  height: "10px",
                  borderRadius: "4px",
                  background: "var(--io-border)",
                  width: i === columns - 1 ? "40px" : "120px",
                  animation: "io-shimmer 1.5s ease-in-out infinite",
                }}
              />
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {Array.from({ length: rows }).map((_, ri) => (
          <tr
            key={ri}
            style={{
              borderBottom:
                ri < rows - 1 ? "1px solid var(--io-border-subtle)" : undefined,
            }}
          >
            {Array.from({ length: columns }).map((_, ci) => (
              <td key={ci} style={{ padding: "12px 14px" }}>
                <div
                  style={{
                    height: "12px",
                    borderRadius: "4px",
                    background: "var(--io-surface-primary)",
                    width:
                      ci === columns - 1
                        ? "40px"
                        : ci === 0
                          ? "120px"
                          : "160px",
                    animation: "io-shimmer 1.5s ease-in-out infinite",
                    animationDelay: `${ri * 0.05}s`,
                  }}
                />
              </td>
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  );
}

// ---------------------------------------------------------------------------
// Client certificate API (GET /api/certificates?type=client)
// ---------------------------------------------------------------------------

export interface ClientCertificate {
  id: string;
  name: string;
  subject: string | null;
  not_after: string | null;
  expired: boolean;
}

const clientCertsApi = {
  list: () =>
    fetch("/api/certificates?type=client", {
      headers: { "Content-Type": "application/json" },
      credentials: "include",
    }).then(async (r) => {
      const json = await r.json();
      return json as {
        success: boolean;
        data: ClientCertificate[];
        error?: { message: string };
      };
    }),
};

// ---------------------------------------------------------------------------
// Status badge
// ---------------------------------------------------------------------------

const STATUS_COLORS: Record<string, string> = {
  active: "var(--io-success)",
  inactive: "var(--io-text-muted)",
  connecting: "var(--io-warning)",
  error: "var(--io-danger)",
};

function StatusBadge({ status }: { status: string }) {
  const color = STATUS_COLORS[status] ?? "var(--io-text-muted)";
  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: "5px",
        padding: "2px 8px",
        borderRadius: "9999px",
        fontSize: "11px",
        fontWeight: 600,
        background: `${color}20`,
        color,
        border: `1px solid ${color}40`,
        textTransform: "capitalize",
      }}
    >
      <span
        style={{
          width: "6px",
          height: "6px",
          borderRadius: "50%",
          background: color,
          flexShrink: 0,
        }}
      />
      {status}
    </span>
  );
}

// ---------------------------------------------------------------------------
// Source stats — inline chips for the table row
// ---------------------------------------------------------------------------

function fmtCount(n: number): string {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}k`;
  return String(n);
}

function SourceStatsChips({ stats }: { stats: PointSourceStats | undefined }) {
  if (!stats) return null;
  const chips: Array<{ label: string; value: string; color?: string }> = [
    { label: "pts", value: fmtCount(stats.point_count) },
    { label: "active", value: fmtCount(stats.active_subscriptions) },
  ];
  if (stats.updates_per_minute !== null) {
    chips.push({ label: "/min", value: fmtCount(stats.updates_per_minute) });
  }
  if (stats.error_count_24h > 0) {
    chips.push({
      label: "errors",
      value: String(stats.error_count_24h),
      color: "var(--io-danger)",
    });
  }
  return (
    <div
      style={{
        display: "flex",
        gap: "6px",
        marginTop: "5px",
        flexWrap: "wrap",
      }}
      onClick={(e) => e.stopPropagation()}
    >
      {chips.map((c) => (
        <span
          key={c.label}
          style={{
            display: "inline-flex",
            alignItems: "baseline",
            gap: "3px",
            fontSize: "11px",
            color: c.color ?? "var(--io-text-muted)",
          }}
        >
          <strong
            style={{ fontWeight: 600, fontVariantNumeric: "tabular-nums" }}
          >
            {c.value}
          </strong>
          <span style={{ opacity: 0.7 }}>{c.label}</span>
        </span>
      ))}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Source stats — tile grid for the detail panel
// ---------------------------------------------------------------------------

function SourceStatsTiles({ sourceId }: { sourceId: string }) {
  const statsQuery = useQuery({
    queryKey: ["point-source-stats", sourceId],
    queryFn: async () => {
      const r = await pointSourceStatsApi.get(sourceId);
      if (!r.success) throw new Error(r.error.message);
      return r.data as PointSourceStats;
    },
    refetchInterval: 15_000,
  });

  const s = statsQuery.data;
  const tiles: Array<{
    label: string;
    value: string;
    sub?: string;
    accent?: boolean;
    danger?: boolean;
  }> = [
    {
      label: "Total Points",
      value: s ? fmtCount(s.point_count) : "—",
      sub: "configured",
    },
    {
      label: "Active Subs",
      value: s ? fmtCount(s.active_subscriptions) : "—",
      sub: "subscriptions",
      accent: s ? s.active_subscriptions > 0 : false,
    },
    {
      label: "Updates / min",
      value:
        s?.updates_per_minute !== null && s?.updates_per_minute !== undefined
          ? fmtCount(s.updates_per_minute)
          : "—",
      sub: "recording",
    },
    {
      label: "Errors (24 h)",
      value: s ? String(s.error_count_24h) : "—",
      danger: s ? s.error_count_24h > 0 : false,
    },
  ];

  return (
    <div>
      <div
        style={{
          fontSize: "11px",
          fontWeight: 600,
          color: "var(--io-text-muted)",
          textTransform: "uppercase",
          letterSpacing: "0.06em",
          marginBottom: "10px",
        }}
      >
        Live Statistics
      </div>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)",
          gap: "8px",
          marginBottom: "20px",
        }}
      >
        {tiles.map((t) => (
          <div
            key={t.label}
            style={{
              background: "var(--io-surface-secondary)",
              border: "1px solid var(--io-border-subtle)",
              borderRadius: "var(--io-radius)",
              padding: "12px 10px",
              display: "flex",
              flexDirection: "column",
              gap: "2px",
            }}
          >
            <div
              style={{
                fontSize: "20px",
                fontWeight: 700,
                fontVariantNumeric: "tabular-nums",
                color: t.danger
                  ? "var(--io-danger)"
                  : t.accent
                    ? "var(--io-success)"
                    : "var(--io-text-primary)",
                lineHeight: 1.1,
              }}
            >
              {statsQuery.isLoading ? (
                <span style={{ opacity: 0.3 }}>—</span>
              ) : (
                t.value
              )}
            </div>
            <div
              style={{
                fontSize: "11px",
                color: "var(--io-text-muted)",
                lineHeight: 1.3,
              }}
            >
              {t.label}
              {t.sub && (
                <span style={{ display: "block", opacity: 0.7 }}>{t.sub}</span>
              )}
            </div>
          </div>
        ))}
      </div>
      {s?.last_value_at && (
        <div
          style={{
            fontSize: "11px",
            color: "var(--io-text-muted)",
            marginBottom: "16px",
          }}
        >
          Last value received: {new Date(s.last_value_at).toLocaleString()}
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Modal wrapper
// ---------------------------------------------------------------------------

function ModalContent({
  title,
  children,
}: {
  title: string;
  children: React.ReactNode;
}) {
  return (
    <Dialog.Portal>
      <Dialog.Overlay
        style={{
          position: "fixed",
          inset: 0,
          background: "var(--io-overlay, rgba(0,0,0,0.5))",
          zIndex: 100,
        }}
      />
      <Dialog.Content
        aria-describedby={undefined}
        style={{
          position: "fixed",
          top: "50%",
          left: "50%",
          transform: "translate(-50%,-50%)",
          background: "var(--io-surface-elevated)",
          border: "1px solid var(--io-border)",
          borderRadius: "10px",
          padding: "24px",
          width: "520px",
          maxWidth: "95vw",
          maxHeight: "90vh",
          overflowY: "auto",
          zIndex: 101,
          boxShadow: "0 20px 60px rgba(0,0,0,0.4)",
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            marginBottom: "20px",
          }}
        >
          <Dialog.Title
            style={{
              margin: 0,
              fontSize: "16px",
              fontWeight: 600,
              color: "var(--io-text-primary)",
            }}
          >
            {title}
          </Dialog.Title>
          <Dialog.Close asChild>
            <button
              style={{
                background: "none",
                border: "none",
                color: "var(--io-text-muted)",
                cursor: "pointer",
                fontSize: "18px",
                lineHeight: 1,
              }}
            >
              ✕
            </button>
          </Dialog.Close>
        </div>
        {children}
      </Dialog.Content>
    </Dialog.Portal>
  );
}

// ---------------------------------------------------------------------------
// Source form fields (shared between create and edit)
// ---------------------------------------------------------------------------

interface SourceFormState {
  name: string;
  endpoint_url: string;
  security_policy: string;
  security_mode: string;
  username: string;
  password: string;
  enabled: boolean;
  client_certificate_id: string | null;
  platform: string | null;
  publish_interval_ms: number | null;
  data_category_id: string | null;
}

// ---------------------------------------------------------------------------
// Data categories
// ---------------------------------------------------------------------------

const PREDEFINED_CATEGORIES = [
  { id: "process", label: "Process" },
  { id: "event", label: "Event" },
  { id: "access_control", label: "Access Control" },
  { id: "personnel", label: "Personnel" },
  { id: "financial", label: "Financial" },
  { id: "maintenance", label: "Maintenance" },
  { id: "ticketing", label: "Ticketing" },
  { id: "environmental", label: "Environmental" },
  { id: "general", label: "General" },
];

interface DataCategory {
  id: string;
  label: string;
  predefined: boolean;
}

// Simple in-memory custom categories store (backed by API in production)
function useDataCategories() {
  const query = useQuery<DataCategory[]>({
    queryKey: ["data-categories"],
    queryFn: async () => {
      try {
        const res = await fetch("/api/data-categories");
        if (!res.ok) throw new Error("API unavailable");
        const json = await res.json();
        return json.data ?? json;
      } catch {
        // Fall back to predefined only
        return PREDEFINED_CATEGORIES.map((c) => ({ ...c, predefined: true }));
      }
    },
    staleTime: 60_000,
    initialData: PREDEFINED_CATEGORIES.map((c) => ({ ...c, predefined: true })),
  });
  return query;
}

// ---------------------------------------------------------------------------
// Manage Categories modal
// ---------------------------------------------------------------------------

function ManageCategoriesModal({
  open,
  onClose,
}: {
  open: boolean;
  onClose: () => void;
}) {
  const qc = useQueryClient();
  const catQuery = useDataCategories();
  const categories = catQuery.data ?? [];

  const [newName, setNewName] = useState("");
  const [editId, setEditId] = useState<string | null>(null);
  const [editName, setEditName] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  async function handleCreate() {
    const trimmed = newName.trim();
    if (!trimmed) return;
    setSaving(true);
    setError(null);
    try {
      const res = await fetch("/api/data-categories", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ label: trimmed }),
      });
      if (!res.ok) throw new Error(await res.text());
      qc.invalidateQueries({ queryKey: ["data-categories"] });
      setNewName("");
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to create category");
    } finally {
      setSaving(false);
    }
  }

  async function handleRename(id: string) {
    const trimmed = editName.trim();
    if (!trimmed) return;
    setSaving(true);
    setError(null);
    try {
      const res = await fetch(`/api/data-categories/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ label: trimmed }),
      });
      if (!res.ok) throw new Error(await res.text());
      qc.invalidateQueries({ queryKey: ["data-categories"] });
      setEditId(null);
      setEditName("");
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to rename category");
    } finally {
      setSaving(false);
    }
  }

  async function handleDelete(id: string) {
    if (!confirm("Delete this custom category?")) return;
    setSaving(true);
    setError(null);
    try {
      const res = await fetch(`/api/data-categories/${id}`, {
        method: "DELETE",
      });
      if (!res.ok) throw new Error(await res.text());
      qc.invalidateQueries({ queryKey: ["data-categories"] });
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to delete category");
    } finally {
      setSaving(false);
    }
  }

  if (!open) return null;

  const modalOverlay: React.CSSProperties = {
    position: "fixed",
    inset: 0,
    zIndex: 200,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    background: "var(--io-overlay, rgba(0,0,0,0.5))",
  };

  const modalBox: React.CSSProperties = {
    position: "relative",
    width: "500px",
    maxWidth: "95vw",
    maxHeight: "80vh",
    background: "var(--io-surface-elevated)",
    border: "1px solid var(--io-border)",
    borderRadius: "10px",
    display: "flex",
    flexDirection: "column",
    overflow: "hidden",
    boxShadow: "0 20px 60px rgba(0,0,0,0.4)",
  };

  const catInputStyle: React.CSSProperties = {
    flex: 1,
    padding: "6px 10px",
    background: "var(--io-surface-secondary)",
    border: "1px solid var(--io-border)",
    borderRadius: "var(--io-radius)",
    color: "var(--io-text)",
    fontSize: "13px",
  };

  const smBtn = (
    variant: "primary" | "ghost" | "danger",
  ): React.CSSProperties => ({
    padding: "5px 10px",
    fontSize: "12px",
    border:
      variant === "danger"
        ? "1px solid var(--io-danger)"
        : variant === "ghost"
          ? "1px solid var(--io-border)"
          : "none",
    borderRadius: "var(--io-radius)",
    background: variant === "primary" ? "var(--io-accent)" : "transparent",
    color:
      variant === "primary"
        ? "var(--io-text-on-accent)"
        : variant === "danger"
          ? "var(--io-danger)"
          : "var(--io-text-secondary)",
    cursor: saving ? "not-allowed" : "pointer",
    opacity: saving ? 0.6 : 1,
  });

  return (
    <div style={modalOverlay} onClick={onClose}>
      <div style={modalBox} onClick={(e) => e.stopPropagation()}>
        {/* Header */}
        <div
          style={{
            padding: "18px 20px",
            borderBottom: "1px solid var(--io-border)",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            flexShrink: 0,
          }}
        >
          <div style={{ fontWeight: 600, fontSize: "15px" }}>
            Manage Data Categories
          </div>
          <button
            onClick={onClose}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              color: "var(--io-text-muted)",
              fontSize: "18px",
              lineHeight: 1,
            }}
          >
            ×
          </button>
        </div>

        {/* Body */}
        <div style={{ flex: 1, overflowY: "auto", padding: "20px" }}>
          <div
            style={{
              fontSize: "12px",
              color: "var(--io-text-muted)",
              marginBottom: "16px",
              lineHeight: 1.5,
            }}
          >
            Predefined categories cannot be deleted. Custom categories can be
            renamed or deleted.
          </div>

          {error && (
            <div
              style={{
                padding: "8px 12px",
                background: "var(--io-danger-subtle)",
                color: "var(--io-danger)",
                borderRadius: "var(--io-radius)",
                fontSize: "12px",
                marginBottom: "12px",
              }}
            >
              {error}
            </div>
          )}

          {/* Category list */}
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              gap: "6px",
              marginBottom: "20px",
            }}
          >
            {categories.map((cat) => (
              <div
                key={cat.id}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "8px",
                  padding: "8px 10px",
                  background: "var(--io-surface-secondary)",
                  border: "1px solid var(--io-border-subtle)",
                  borderRadius: "var(--io-radius)",
                }}
              >
                {editId === cat.id ? (
                  <>
                    <input
                      style={catInputStyle}
                      value={editName}
                      onChange={(e) => setEditName(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === "Enter") handleRename(cat.id);
                      }}
                      autoFocus
                    />
                    <button
                      style={smBtn("primary")}
                      onClick={() => handleRename(cat.id)}
                      disabled={saving}
                    >
                      Save
                    </button>
                    <button
                      style={smBtn("ghost")}
                      onClick={() => {
                        setEditId(null);
                        setEditName("");
                      }}
                    >
                      Cancel
                    </button>
                  </>
                ) : (
                  <>
                    <span
                      style={{
                        flex: 1,
                        fontSize: "13px",
                        color: "var(--io-text-primary)",
                      }}
                    >
                      {cat.label}
                    </span>
                    {cat.predefined ? (
                      <span
                        style={{
                          fontSize: "11px",
                          color: "var(--io-text-muted)",
                          fontStyle: "italic",
                        }}
                      >
                        predefined
                      </span>
                    ) : (
                      <>
                        <button
                          style={smBtn("ghost")}
                          onClick={() => {
                            setEditId(cat.id);
                            setEditName(cat.label);
                          }}
                          disabled={saving}
                        >
                          Rename
                        </button>
                        <button
                          style={smBtn("danger")}
                          onClick={() => handleDelete(cat.id)}
                          disabled={saving}
                        >
                          Delete
                        </button>
                      </>
                    )}
                  </>
                )}
              </div>
            ))}
          </div>

          {/* Add new */}
          <div
            style={{
              fontSize: "12px",
              fontWeight: 600,
              color: "var(--io-text-muted)",
              textTransform: "uppercase",
              letterSpacing: "0.06em",
              marginBottom: "8px",
            }}
          >
            Add Custom Category
          </div>
          <div style={{ display: "flex", gap: "8px" }}>
            <input
              style={catInputStyle}
              value={newName}
              onChange={(e) => setNewName(e.target.value)}
              placeholder="Category name"
              onKeyDown={(e) => {
                if (e.key === "Enter") handleCreate();
              }}
            />
            <button
              style={smBtn("primary")}
              onClick={handleCreate}
              disabled={saving || !newName.trim()}
            >
              Add
            </button>
          </div>
        </div>

        {/* Footer */}
        <div
          style={{
            padding: "14px 20px",
            borderTop: "1px solid var(--io-border)",
            display: "flex",
            justifyContent: "flex-end",
            flexShrink: 0,
          }}
        >
          <button onClick={onClose} style={smBtn("ghost")}>
            Close
          </button>
        </div>
      </div>
    </div>
  );
}

const SECURITY_POLICIES = [
  "None",
  "Basic256Sha256",
  "Aes128Sha256RsaOaep",
  "Aes256Sha256RsaPss",
];
const SECURITY_MODES = ["None", "Sign", "SignAndEncrypt"];

// DCS platform options from doc 17 §Connection Profiles
const DCS_PLATFORMS = [
  { value: "", label: "Unknown / Generic" },
  { value: "siemens_s7_1500", label: "Siemens S7-1500 (TIA Portal)" },
  { value: "siemens_s7_1200", label: "Siemens S7-1200 (TIA Portal)" },
  { value: "siemens_wincc_oa", label: "Siemens WinCC OA" },
  { value: "siemens_wincc_v7", label: "Siemens WinCC V7 / RT Pro" },
  { value: "honeywell_experion", label: "Honeywell Experion PKS" },
  { value: "abb_800xa", label: "ABB 800xA" },
