function EditSourceDialog({
  source,
  open,
  onOpenChange,
}: {
  source: PointSource | null;
  open: boolean;
  onOpenChange: (v: boolean) => void;
}) {
  const qc = useQueryClient();
  const [form, setForm] = useState<SourceFormState>({
    name: source?.name ?? "",
    endpoint_url: source?.endpoint_url ?? "",
    security_policy: source?.security_policy ?? "None",
    security_mode: source?.security_mode ?? "None",
    username: source?.username ?? "",
    password: "",
    enabled: source?.enabled ?? true,
    client_certificate_id: null,
    platform: null,
    publish_interval_ms: null,
    data_category_id: null,
  });
  const [error, setError] = useState<string | null>(null);
  const [testStatus, setTestStatus] = useState<
    "idle" | "testing" | "ok" | "fail"
  >("idle");
  const [testMessage, setTestMessage] = useState<string>("");

  const certsQuery = useQuery({
    queryKey: ["client-certificates"],
    queryFn: async () => {
      const result = await clientCertsApi.list();
      if (!result.success) return [] as ClientCertificate[];
      return result.data;
    },
    staleTime: 60_000,
  });

  React.useEffect(() => {
    if (source) {
      setForm({
        name: source.name,
        endpoint_url: source.endpoint_url,
        security_policy: source.security_policy ?? "None",
        security_mode: source.security_mode ?? "None",
        username: source.username ?? "",
        password: "",
        enabled: source.enabled,
        client_certificate_id: null,
        platform: null,
        publish_interval_ms: null,
        data_category_id: null,
      });
      setTestStatus("idle");
      setTestMessage("");
    }
  }, [source]);

  const mutation = useMutation({
    mutationFn: (req: UpdatePointSourceRequest) =>
      pointSourcesApi.update(source!.id, req),
    onSuccess: (result) => {
      if (!result.success) {
        setError(result.error.message);
        return;
      }
      qc.invalidateQueries({ queryKey: ["point-sources"] });
      onOpenChange(false);
      setError(null);
    },
  });

  const testMutation = useMutation({
    mutationFn: () => pointSourcesApi.testConnection(source!.id),
    onSuccess: (result) => {
      if (!result.success) {
        setTestStatus("fail");
        setTestMessage(result.error.message);
        return;
      }
      if (result.data.success) {
        setTestStatus("ok");
        setTestMessage(
          result.data.message +
            (result.data.latency_ms != null
              ? ` (${result.data.latency_ms}ms)`
              : ""),
        );
      } else {
        setTestStatus("fail");
        setTestMessage(result.data.message);
      }
    },
    onError: (e: Error) => {
      setTestStatus("fail");
      setTestMessage(e.message);
    },
  });

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError(null);
    const req: UpdatePointSourceRequest = {
      name: form.name,
      endpoint_url: form.endpoint_url,
      security_policy: form.security_policy,
      security_mode: form.security_mode,
      username: form.username || undefined,
      password: form.password || undefined,
      enabled: form.enabled,
      client_certificate_id: form.client_certificate_id,
      platform: form.platform,
      publish_interval_ms: form.publish_interval_ms,
    };
    mutation.mutate(req);
  }

  if (!source) return null;

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <ModalContent title={`Edit: ${source.name}`}>
        {error && (
          <div
            style={{
              padding: "10px 12px",
              borderRadius: "var(--io-radius)",
              background: "var(--io-danger-subtle)",
              border: "1px solid var(--io-danger)",
              color: "var(--io-danger)",
              fontSize: "13px",
              marginBottom: "16px",
            }}
          >
            {error}
          </div>
        )}
        <form onSubmit={handleSubmit}>
          <SourceFormFields
            form={form}
            onChange={(p) => setForm((f) => ({ ...f, ...p }))}
            showEnabled
            clientCerts={certsQuery.data}
          />
          {/* Test connection */}
          <div
            style={{
              marginTop: "16px",
              display: "flex",
              alignItems: "center",
              gap: "12px",
            }}
          >
            <button
              type="button"
              style={btnSecondary}
              disabled={testMutation.isPending}
              onClick={() => {
                setTestStatus("testing");
                setTestMessage("");
                testMutation.mutate();
              }}
            >
              {testMutation.isPending ? "Testing…" : "Test Connection"}
            </button>
            {testStatus === "ok" && (
              <span style={{ fontSize: "12px", color: "var(--io-success)" }}>
                Connected — {testMessage}
              </span>
            )}
            {testStatus === "fail" && (
              <span style={{ fontSize: "12px", color: "var(--io-danger)" }}>
                Failed — {testMessage}
              </span>
            )}
          </div>
          <div
            style={{
              display: "flex",
              justifyContent: "flex-end",
              gap: "8px",
              marginTop: "24px",
            }}
          >
            <Dialog.Close asChild>
              <button type="button" style={btnSecondary}>
                Cancel
              </button>
            </Dialog.Close>
            <button
              type="submit"
              style={btnPrimary}
              disabled={mutation.isPending}
            >
              {mutation.isPending ? "Saving…" : "Save Changes"}
            </button>
          </div>
        </form>
      </ModalContent>
    </Dialog.Root>
  );
}

