}

function ServerCertCard({
  cert,
  onTrust,
  onReject,
  onDelete,
  loading,
}: {
  cert: OpcServerCert;
  onTrust: () => void;
  onReject: () => void;
  onDelete: () => void;
  loading: boolean;
}) {
  const formatDate = (d: string | null) =>
    d
      ? new Date(d).toLocaleDateString(undefined, {
          year: "numeric",
          month: "short",
          day: "numeric",
        })
      : "—";

  const btnStyle = (
    variant: "primary" | "danger" | "ghost",
  ): React.CSSProperties => ({
    padding: "5px 12px",
    borderRadius: 6,
    border: variant === "ghost" ? "1px solid var(--io-border)" : "none",
    background:
      variant === "primary"
        ? "var(--io-accent)"
        : variant === "danger"
          ? "var(--io-danger)"
          : "transparent",
    color:
      variant === "ghost"
        ? "var(--io-text-secondary)"
        : "var(--io-text-on-accent)",
    fontSize: 12,
    fontWeight: 500,
    cursor: loading ? "not-allowed" : "pointer",
    opacity: loading ? 0.6 : 1,
  });

  return (
    <div
      style={{
        border: "1px solid var(--io-border)",
        borderRadius: 8,
        padding: 16,
        display: "flex",
        flexDirection: "column",
        gap: 12,
        background: "var(--io-surface-secondary)",
      }}
    >
      {/* Header row: fingerprint + status badge */}
      <div
        style={{
          display: "flex",
          alignItems: "flex-start",
          gap: 10,
          justifyContent: "space-between",
        }}
      >
        <div style={{ flex: 1, minWidth: 0 }}>
          <div
            style={{
              fontSize: 11,
              color: "var(--io-text-muted)",
              marginBottom: 3,
            }}
          >
            SHA-256 Fingerprint
          </div>
          <div
            style={{
              fontFamily: "monospace",
              fontSize: 11,
              color: "var(--io-text-secondary)",
              wordBreak: "break-all",
              lineHeight: 1.5,
            }}
          >
            {cert.fingerprint_display}
          </div>
        </div>
        <CertStatusBadge status={cert.status} />
      </div>

      {/* Cert fields */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "8px 16px",
        }}
      >
        {[
          { label: "Subject", value: cert.subject },
          { label: "Issuer", value: cert.issuer },
          { label: "Valid From", value: formatDate(cert.not_before) },
          { label: "Valid To", value: formatDate(cert.not_after) },
        ].map(({ label, value }) => (
          <div key={label}>
            <div
              style={{
                fontSize: 11,
                color: "var(--io-text-muted)",
                marginBottom: 2,
              }}
            >
              {label}
            </div>
            <div
              style={{
                fontSize: 12,
                color: "var(--io-text-primary)",
                fontFamily:
                  label === "Subject" || label === "Issuer"
                    ? "monospace"
                    : undefined,
              }}
            >
              {value ?? "—"}
              {label === "Valid To" && cert.expired && (
                <span
                  style={{
                    marginLeft: 6,
                    color: "var(--io-danger)",
                    fontSize: 11,
                  }}
                >
                  EXPIRED
                </span>
              )}
            </div>
          </div>
        ))}
      </div>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "8px 16px",
        }}
      >
        <div>
          <div
            style={{
              fontSize: 11,
              color: "var(--io-text-muted)",
              marginBottom: 2,
            }}
          >
            First Seen
          </div>
          <div style={{ fontSize: 12, color: "var(--io-text-secondary)" }}>
            {formatDate(cert.first_seen_at)}
          </div>
        </div>
        <div>
          <div
            style={{
              fontSize: 11,
              color: "var(--io-text-muted)",
              marginBottom: 2,
            }}
          >
            Last Seen
          </div>
          <div style={{ fontSize: 12, color: "var(--io-text-secondary)" }}>
            {formatDate(cert.last_seen_at)}
          </div>
        </div>
      </div>

      {cert.auto_trusted && (
        <div
          style={{
            fontSize: 11,
            color: "var(--io-warning)",
            background: "var(--io-warning-subtle)",
            border: "1px solid var(--io-warning)",
            borderRadius: 6,
            padding: "6px 10px",
          }}
        >
          Auto-trusted — this certificate was accepted automatically because{" "}
          <strong>OPC Auto-Trust</strong> is enabled on this server. Disable it
          in Settings to require manual approval for new connections.
        </div>
      )}

      {/* Actions */}
      <div style={{ display: "flex", gap: 8 }}>
        {cert.status !== "trusted" && (
          <button
            style={btnStyle("primary")}
            onClick={onTrust}
            disabled={loading}
          >
            Trust
          </button>
        )}
        {cert.status !== "rejected" && (
          <button
            style={btnStyle("danger")}
            onClick={onReject}
            disabled={loading}
          >
            Reject
          </button>
        )}
        <button style={btnStyle("ghost")} onClick={onDelete} disabled={loading}>
          Remove
        </button>
      </div>
    </div>
  );
}

function ServerCertTab({ sourceId }: { sourceId: string }) {
  const queryClient = useQueryClient();

  const { data: certs, isLoading } = useQuery({
    queryKey: ["opc-server-certs"],
    queryFn: async () => {
      const result = await opcCertsApi.list();
      if (!result.success) throw new Error(result.error.message);
      return result.data;
    },
    staleTime: 15_000,
  });

  const sourceCerts = (certs ?? []).filter(
    (c) => c.source_id === sourceId || c.source_id === null,
  );

  const mutOpts = {
    onSuccess: () =>
      queryClient.invalidateQueries({ queryKey: ["opc-server-certs"] }),
  };
  const trustMut = useMutation({
    mutationFn: (id: string) => opcCertsApi.trust(id),
    ...mutOpts,
  });
  const rejectMut = useMutation({
    mutationFn: (id: string) => opcCertsApi.reject(id),
    ...mutOpts,
  });
  const deleteMut = useMutation({
    mutationFn: (id: string) => opcCertsApi.delete(id),
    ...mutOpts,
  });

  const isBusy =
    trustMut.isPending || rejectMut.isPending || deleteMut.isPending;

  if (isLoading) {
    return (
      <div style={{ color: "var(--io-text-muted)", fontSize: 13 }}>
        Loading certificates…
      </div>
    );
  }

  if (sourceCerts.length === 0) {
    return (
      <div
        style={{
          textAlign: "center",
          padding: "40px 0",
          color: "var(--io-text-muted)",
          fontSize: 13,
        }}
      >
        <div style={{ marginBottom: 8, fontSize: 32 }}>🔒</div>
        <div style={{ fontWeight: 500, marginBottom: 6 }}>
          No server certificate on record
        </div>
        <div
          style={{
            fontSize: 12,
            lineHeight: 1.6,
            maxWidth: 340,
            margin: "0 auto",
          }}
        >
          The OPC UA server certificate will appear here the first time this
          source connects. Once seen, you can approve or reject it.
        </div>
      </div>
    );
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <div
        style={{ fontSize: 12, color: "var(--io-text-muted)", lineHeight: 1.6 }}
      >
        The certificate(s) below were presented by the OPC UA server during
        connection. Trust a certificate to allow connections; reject it to block
        them.
      </div>
      {sourceCerts.map((cert) => (
        <ServerCertCard
          key={cert.id}
          cert={cert}
          loading={isBusy}
          onTrust={() => trustMut.mutate(cert.id)}
          onReject={() => rejectMut.mutate(cert.id)}
          onDelete={() => deleteMut.mutate(cert.id)}
        />
      ))}
    </div>
  );
}

