const SHORTCUT_HOURS = [1, 4, 8, 24, 48, 72, 168] as const;

function fmtDatetimeLocal(d: Date): string {
  const pad = (n: number) => String(n).padStart(2, "0");
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

function statusColor(status: RecoveryJob["status"]): string {
  switch (status) {
    case "complete":
      return "var(--io-success)";
    case "running":
      return "var(--io-accent)";
    case "failed":
      return "var(--io-danger)";
    default:
      return "var(--io-text-muted)";
  }
}

function HistoryRecoveryTab({ sourceId }: { sourceId: string }) {
  const qc = useQueryClient();

  // Default: last 1 hour
  const now = new Date();
  const oneHourAgo = new Date(now.getTime() - 3600_000);
  const [fromValue, setFromValue] = useState(fmtDatetimeLocal(oneHourAgo));
  const [toValue, setToValue] = useState(fmtDatetimeLocal(now));
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [submitOk, setSubmitOk] = useState(false);

  const jobsQuery = useQuery({
    queryKey: ["history-recovery-jobs", sourceId],
    queryFn: async () => {
      const r = await historyRecoveryApi.listJobs(sourceId);
      if (!r.success) throw new Error(r.error.message);
      return r.data as RecoveryJob[];
    },
    refetchInterval: (query) => {
      const data = query.state.data;
      if (!data) return 10_000;
      const hasActive = data.some(
        (j) => j.status === "pending" || j.status === "running",
      );
      return hasActive ? 3_000 : 15_000;
    },
  });

  const createMutation = useMutation({
    mutationFn: async () => {
      const from = new Date(fromValue).toISOString();
      const to = new Date(toValue).toISOString();
      const r = await historyRecoveryApi.createJob(sourceId, from, to);
      if (!r.success) throw new Error(r.error.message);
      return r.data;
    },
    onSuccess: () => {
      setSubmitOk(true);
      setSubmitError(null);
      setTimeout(() => setSubmitOk(false), 4000);
      qc.invalidateQueries({ queryKey: ["history-recovery-jobs", sourceId] });
    },
    onError: (e: Error) => {
      setSubmitError(e.message);
      setSubmitOk(false);
    },
  });

  function applyShortcut(hours: number) {
    const t = new Date();
    const f = new Date(t.getTime() - hours * 3600_000);
    setFromValue(fmtDatetimeLocal(f));
    setToValue(fmtDatetimeLocal(t));
  }

  const jobs = jobsQuery.data ?? [];

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
      {/* Request form */}
      <div
        style={{
          background: "var(--io-surface-secondary)",
          border: "1px solid var(--io-border-subtle)",
          borderRadius: "var(--io-radius)",
          padding: "16px",
          display: "flex",
          flexDirection: "column",
          gap: "14px",
        }}
      >
        <div
          style={{
            fontSize: "13px",
            fontWeight: 600,
            color: "var(--io-text-primary)",
          }}
        >
          Request Historical Data Recovery
        </div>

        {/* Quick shortcuts */}
        <div style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>
          {SHORTCUT_HOURS.map((h) => (
            <button
              key={h}
              onClick={() => applyShortcut(h)}
              style={{
                padding: "4px 10px",
                fontSize: "12px",
                background: "var(--io-surface-sunken)",
                border: "1px solid var(--io-border)",
                borderRadius: "4px",
                color: "var(--io-text-secondary)",
                cursor: "pointer",
              }}
            >
              {h < 24 ? `Last ${h}h` : `Last ${h / 24}d`}
            </button>
          ))}
        </div>

        {/* Date range */}
        <div style={{ display: "flex", gap: "12px", alignItems: "center" }}>
          <div style={{ flex: 1 }}>
            <div
              style={{
                fontSize: "11px",
                color: "var(--io-text-muted)",
                marginBottom: "4px",
              }}
            >
              From
            </div>
            <input
              type="datetime-local"
              value={fromValue}
              onChange={(e) => setFromValue(e.target.value)}
              style={{
                width: "100%",
                padding: "7px 9px",
                background: "var(--io-surface-sunken)",
                border: "1px solid var(--io-border)",
                borderRadius: "4px",
                color: "var(--io-text-primary)",
                fontSize: "13px",
              }}
            />
          </div>
          <div
            style={{
              paddingTop: "18px",
              color: "var(--io-text-muted)",
              fontSize: "12px",
            }}
          >
            →
          </div>
          <div style={{ flex: 1 }}>
            <div
              style={{
                fontSize: "11px",
                color: "var(--io-text-muted)",
                marginBottom: "4px",
              }}
            >
              To
            </div>
            <input
              type="datetime-local"
              value={toValue}
              onChange={(e) => setToValue(e.target.value)}
              style={{
                width: "100%",
                padding: "7px 9px",
                background: "var(--io-surface-sunken)",
                border: "1px solid var(--io-border)",
                borderRadius: "4px",
                color: "var(--io-text-primary)",
                fontSize: "13px",
              }}
            />
          </div>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
          <button
            onClick={() => createMutation.mutate()}
            disabled={createMutation.isPending}
            style={{
              padding: "8px 16px",
              background: "var(--io-accent)",
              border: "none",
              borderRadius: "4px",
              color: "var(--io-text-on-accent)",
              fontSize: "13px",
              fontWeight: 500,
              cursor: createMutation.isPending ? "not-allowed" : "pointer",
              opacity: createMutation.isPending ? 0.7 : 1,
            }}
          >
            {createMutation.isPending ? "Submitting…" : "Request Recovery"}
          </button>
          {submitOk && (
            <span style={{ fontSize: "12px", color: "var(--io-success)" }}>
              Job queued — the OPC service will process it shortly.
            </span>
          )}
          {submitError && (
            <span style={{ fontSize: "12px", color: "var(--io-danger)" }}>
              {submitError}
            </span>
          )}
        </div>
      </div>

      {/* Recent jobs */}
      <div>
        <div
          style={{
            fontSize: "12px",
            fontWeight: 600,
            color: "var(--io-text-muted)",
            textTransform: "uppercase",
            letterSpacing: "0.06em",
            marginBottom: "10px",
          }}
        >
          Recent Jobs
        </div>
        {jobs.length === 0 ? (
          <div
            style={{
              padding: "20px",
              textAlign: "center",
              color: "var(--io-text-muted)",
              fontSize: "13px",
              background: "var(--io-surface-secondary)",
              border: "1px solid var(--io-border-subtle)",
              borderRadius: "var(--io-radius)",
            }}
          >
            No recovery jobs yet.
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
            {jobs.map((job) => (
              <div
                key={job.id}
                style={{
                  background: "var(--io-surface-secondary)",
                  border: "1px solid var(--io-border-subtle)",
                  borderRadius: "var(--io-radius)",
                  padding: "12px 14px",
                  display: "flex",
                  flexDirection: "column",
                  gap: "6px",
                }}
              >
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "space-between",
                  }}
                >
                  <span
                    style={{
                      fontSize: "12px",
                      fontWeight: 600,
                      color: statusColor(job.status),
                      textTransform: "uppercase",
                      letterSpacing: "0.05em",
                    }}
                  >
                    {job.status}
                  </span>
                  <span
                    style={{ fontSize: "11px", color: "var(--io-text-muted)" }}
                  >
                    {new Date(job.created_at).toLocaleString()}
                  </span>
                </div>
                <div
                  style={{
                    fontSize: "12px",
                    color: "var(--io-text-secondary)",
                    fontFamily: "monospace",
                  }}
                >
                  {new Date(job.from_time).toLocaleString()} →{" "}
                  {new Date(job.to_time).toLocaleString()}
                </div>
                {job.status === "complete" && (
                  <div style={{ fontSize: "12px", color: "var(--io-success)" }}>
                    {job.points_recovered.toLocaleString()} points recovered
                  </div>
                )}
                {job.error_message && (
                  <div
                    style={{
                      fontSize: "12px",
                      color: "var(--io-danger)",
                      fontFamily: "monospace",
                    }}
                  >
                    {job.error_message}
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

