// ---------------------------------------------------------------------------
// Global minimum publish interval control
// ---------------------------------------------------------------------------

const MIN_INTERVAL_FLOOR = 100;
const MIN_INTERVAL_KEY = "opc.minimum_publish_interval_ms";
const MIN_INTERVAL_DEFAULT = 1000;

function MinPublishIntervalControl() {
  const qc = useQueryClient();
  const [localValue, setLocalValue] = useState<string>("");
  const [saveStatus, setSaveStatus] = useState<"idle" | "saved" | "error">(
    "idle",
  );
  const [saveError, setSaveError] = useState<string>("");

  const settingQuery = useQuery({
    queryKey: ["setting", MIN_INTERVAL_KEY],
    queryFn: async () => {
      const result = await settingsApi.list();
      if (!result.success) return MIN_INTERVAL_DEFAULT;
      const setting = (
        result.data as import("../../api/settings").Setting[]
      ).find((s) => s.key === MIN_INTERVAL_KEY);
      return setting ? (setting.value as number) : MIN_INTERVAL_DEFAULT;
    },
    staleTime: 30_000,
  });

  React.useEffect(() => {
    if (settingQuery.data != null) {
      setLocalValue(String(settingQuery.data));
    }
  }, [settingQuery.data]);

  const saveMutation = useMutation({
    mutationFn: (val: number) => settingsApi.update(MIN_INTERVAL_KEY, val),
    onSuccess: (result) => {
      if (!result.success) {
        setSaveStatus("error");
        setSaveError(result.error.message);
        return;
      }
      setSaveStatus("saved");
      setSaveError("");
      qc.invalidateQueries({ queryKey: ["setting", MIN_INTERVAL_KEY] });
      setTimeout(() => setSaveStatus("idle"), 3000);
    },
    onError: (e: Error) => {
      setSaveStatus("error");
      setSaveError(e.message);
    },
  });

  function handleSave() {
    const parsed = parseInt(localValue, 10);
    if (isNaN(parsed) || parsed < MIN_INTERVAL_FLOOR) {
      setSaveStatus("error");
      setSaveError(`Minimum allowed value is ${MIN_INTERVAL_FLOOR}ms`);
      return;
    }
    setSaveStatus("idle");
    setSaveError("");
    saveMutation.mutate(parsed);
  }

  return (
    <div
      style={{
        background: "var(--io-surface-secondary)",
        border: "1px solid var(--io-border)",
        borderRadius: "8px",
        padding: "16px 20px",
        marginBottom: "20px",
      }}
    >
      <div
        style={{
          fontSize: "13px",
          fontWeight: 600,
          color: "var(--io-text-primary)",
          marginBottom: "4px",
        }}
      >
        Global Minimum Publish Interval
      </div>
      <div
        style={{
          fontSize: "12px",
          color: "var(--io-text-muted)",
          marginBottom: "12px",
        }}
      >
        No OPC source can be configured below this floor. Protects DCS/historian
        systems from aggressive polling. Default: {MIN_INTERVAL_DEFAULT}ms.
        Minimum allowed: {MIN_INTERVAL_FLOOR}ms.
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
        <input
          type="number"
          min={MIN_INTERVAL_FLOOR}
          step={100}
          style={{ ...inputStyle, width: "140px" }}
          value={localValue}
          onChange={(e) => {
            setLocalValue(e.target.value);
            setSaveStatus("idle");
          }}
          placeholder={String(MIN_INTERVAL_DEFAULT)}
        />
        <span style={{ fontSize: "12px", color: "var(--io-text-muted)" }}>
          ms
        </span>
        <button
          style={btnPrimary}
          type="button"
          onClick={handleSave}
          disabled={saveMutation.isPending}
        >
          {saveMutation.isPending ? "Saving…" : "Save"}
        </button>
        {saveStatus === "saved" && (
          <span style={{ fontSize: "12px", color: "var(--io-success)" }}>
            Saved
          </span>
        )}
        {saveStatus === "error" && (
          <span style={{ fontSize: "12px", color: "var(--io-danger)" }}>
            {saveError}
          </span>
        )}
      </div>
    </div>
  );
}

