export default function OpcSourcesPage() {
  const qc = useQueryClient();
  const [createOpen, setCreateOpen] = useState(false);
  const [editSource, setEditSource] = useState<PointSource | null>(null);
  const [editOpen, setEditOpen] = useState(false);
  const [detailSource, setDetailSource] = useState<PointSource | null>(null);
  const [detailOpen, setDetailOpen] = useState(false);
  const {
    menuState: opcMenu,
    handleContextMenu: openOpcMenu,
    closeMenu: closeOpcMenu,
  } = useContextMenu<PointSource>();

  const sourcesQuery = useQuery({
    queryKey: ["point-sources"],
    queryFn: async () => {
      const result = await pointSourcesApi.list();
      if (!result.success) throw new Error(result.error.message);
      return result.data.data as PointSource[];
    },
    // Poll faster when any source is in a transitional/error state
    refetchInterval: (query) => {
      const data = query.state.data;
      if (!data) return 5_000;
      const hasActive = data.some(
        (s) => s.status === "connecting" || s.status === "error",
      );
      return hasActive ? 3_000 : 8_000;
    },
  });

  const statsQuery = useQuery({
    queryKey: ["point-sources-stats"],
    queryFn: async () => {
      const r = await pointSourceStatsApi.listAll();
      if (!r.success) return [] as PointSourceStats[];
      return r.data.data;
    },
    refetchInterval: 30_000,
  });

  const statsById = React.useMemo(() => {
    const m = new Map<string, PointSourceStats>();
    for (const s of statsQuery.data ?? []) m.set(s.source_id, s);
    return m;
  }, [statsQuery.data]);

  const deleteMutation = useMutation({
    mutationFn: (id: string) => pointSourcesApi.delete(id),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["point-sources"] }),
  });

  const reconnectMutation = useMutation({
    mutationFn: (id: string) => pointSourcesApi.reconnect(id),
    onSuccess: () => {
      // Refresh immediately after reconnect trigger
      setTimeout(
        () => qc.invalidateQueries({ queryKey: ["point-sources"] }),
        500,
      );
    },
  });

  const toggleEnabledMutation = useMutation({
    mutationFn: (src: PointSource) =>
      pointSourcesApi.update(src.id, { enabled: !src.enabled }),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["point-sources"] }),
  });

  async function handleTestConnection(src: PointSource) {
    try {
      await pointSourcesApi.testConnection(src.id);
    } finally {
      qc.invalidateQueries({ queryKey: ["point-sources"] });
    }
  }

  const sources = sourcesQuery.data ?? [];

  return (
    <div>
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: "20px",
        }}
      >
        <div>
          <h2
            style={{
              margin: "0 0 4px",
              fontSize: "18px",
              fontWeight: 600,
              color: "var(--io-text-primary)",
            }}
          >
            OPC UA Sources
          </h2>
          <p
            style={{
              margin: 0,
              fontSize: "13px",
              color: "var(--io-text-muted)",
            }}
          >
            Configure connections to OPC UA servers
          </p>
        </div>
        <div style={{ display: "flex", gap: "8px", alignItems: "center" }}>
          <ExportButton
            module="settings"
            entity="opc-sources"
            filteredRowCount={sources.length}
            totalRowCount={sources.length}
            availableColumns={OPC_SOURCES_COLUMNS}
            visibleColumns={OPC_SOURCES_DEFAULT_VISIBLE}
          />
          <button style={btnPrimary} onClick={() => setCreateOpen(true)}>
            + Add Source
          </button>
        </div>
      </div>

      <MinPublishIntervalControl />

      <div
        style={{
          background: "var(--io-surface-secondary)",
          border: "1px solid var(--io-border)",
          borderRadius: "8px",
          overflow: "hidden",
        }}
      >
        {sourcesQuery.isLoading && <TableSkeleton rows={4} columns={5} />}
        {!sourcesQuery.isLoading && sources.length === 0 && (
          <div
            style={{
              padding: "48px",
              textAlign: "center",
              color: "var(--io-text-muted)",
              fontSize: "14px",
            }}
          >
            <div style={{ fontSize: "32px", marginBottom: "12px" }}>⚙</div>
            <p
              style={{
                margin: "0 0 4px",
                color: "var(--io-text-secondary)",
                fontWeight: 500,
              }}
            >
              No OPC UA sources configured
            </p>
            <p style={{ margin: 0 }}>
              Add a source to start receiving real-time data.
            </p>
          </div>
        )}
        {sources.length > 0 && (
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr
                style={{
                  borderBottom: "1px solid var(--io-border)",
                  background: "var(--io-surface-primary)",
                }}
              >
                {["Name", "Endpoint", "Status", "Last Connected", ""].map(
                  (col) => (
                    <th
                      key={col}
                      style={{
                        padding: "10px 14px",
                        textAlign: "left",
                        fontSize: "11px",
                        fontWeight: 600,
                        color: "var(--io-text-muted)",
                        textTransform: "uppercase",
                        letterSpacing: "0.06em",
                        whiteSpace: "nowrap",
                      }}
                    >
                      {col}
                    </th>
                  ),
                )}
              </tr>
            </thead>
            <tbody>
              {sources.map((src, i) => (
                <tr
                  key={src.id}
                  style={{
                    borderBottom:
                      i < sources.length - 1
                        ? "1px solid var(--io-border-subtle)"
                        : undefined,
                    cursor: "pointer",
                  }}
                  onContextMenu={(e) => openOpcMenu(e, src)}
                  onClick={() => {
                    setDetailSource(src);
                    setDetailOpen(true);
                  }}
                >
                  <td style={cellStyle}>
                    <div
                      style={{
                        fontWeight: 500,
                        color: "var(--io-text-primary)",
                      }}
                    >
                      {src.name}
                    </div>
                    {!src.enabled && (
                      <div
                        style={{
                          fontSize: "11px",
                          color: "var(--io-text-muted)",
                          marginTop: "2px",
                        }}
                      >
                        disabled
                      </div>
                    )}
                    <SourceStatsChips stats={statsById.get(src.id)} />
                  </td>
                  <td style={cellStyle}>
                    <span
                      style={{
                        fontFamily: "monospace",
                        fontSize: "12px",
                        color: "var(--io-text-muted)",
                      }}
                    >
                      {src.endpoint_url}
                    </span>
                  </td>
                  <td style={cellStyle}>
                    <StatusBadge status={src.status} />
                    {src.last_error_message && src.status !== "active" && (
                      <div
                        style={{
                          fontSize: "11px",
                          color: "var(--io-danger)",
                          marginTop: "4px",
                          maxWidth: "220px",
                          overflow: "hidden",
                          textOverflow: "ellipsis",
                          whiteSpace: "nowrap",
                        }}
                        title={src.last_error_message}
                      >
                        {src.last_error_message}
                      </div>
                    )}
                  </td>
                  <td
                    style={{
                      ...cellStyle,
                      fontSize: "12px",
                      color: "var(--io-text-muted)",
                    }}
                  >
                    {src.last_connected_at
                      ? new Date(src.last_connected_at).toLocaleString()
                      : "—"}
                  </td>
                  <td style={cellStyle} onClick={(e) => e.stopPropagation()}>
                    <div
                      style={{
                        display: "flex",
                        gap: "6px",
                        justifyContent: "flex-end",
                      }}
                    >
                      {src.status !== "active" && src.enabled && (
                        <button
                          style={{
                            padding: "4px 10px",
                            background: "transparent",
                            border: "1px solid var(--io-accent)",
                            borderRadius: "var(--io-radius)",
                            color: "var(--io-accent)",
                            fontSize: "12px",
                            cursor: reconnectMutation.isPending
                              ? "not-allowed"
                              : "pointer",
                            opacity: reconnectMutation.isPending ? 0.6 : 1,
                          }}
                          onClick={() => reconnectMutation.mutate(src.id)}
                          disabled={reconnectMutation.isPending}
                          title="Trigger an immediate reconnect attempt"
                        >
                          Reconnect
                        </button>
                      )}
                      <button
                        style={{
                          padding: "4px 10px",
                          background: "transparent",
                          border: "1px solid var(--io-border)",
                          borderRadius: "var(--io-radius)",
                          color: "var(--io-text-secondary)",
                          fontSize: "12px",
                          cursor: "pointer",
                        }}
                        onClick={() => {
                          setEditSource(src);
                          setEditOpen(true);
                        }}
                      >
                        Edit
                      </button>
                      <button
                        style={{
                          padding: "4px 10px",
                          background: "transparent",
                          border: "1px solid rgba(239,68,68,0.3)",
                          borderRadius: "var(--io-radius)",
                          color: "var(--io-danger)",
                          fontSize: "12px",
                          cursor: "pointer",
                        }}
                        onClick={() => {
                          if (confirm(`Delete "${src.name}"?`)) {
                            deleteMutation.mutate(src.id);
                          }
                        }}
                      >
                        Delete
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <CreateSourceDialog open={createOpen} onOpenChange={setCreateOpen} />
      <EditSourceDialog
        source={editSource}
        open={editOpen}
        onOpenChange={setEditOpen}
      />
      <SourceDetailPanel
        source={detailSource}
        open={detailOpen}
        onOpenChange={setDetailOpen}
        onEdit={() => {
          setDetailOpen(false);
          setEditSource(detailSource);
          setEditOpen(true);
        }}
        onReconnect={() =>
          detailSource && reconnectMutation.mutate(detailSource.id)
        }
        reconnecting={reconnectMutation.isPending}
      />

      {opcMenu && (
        <ContextMenu
          x={opcMenu.x}
          y={opcMenu.y}
          items={[
            {
              label: "Edit",
              onClick: () => {
                setEditSource(opcMenu.data!);
                setEditOpen(true);
              },
            },
            {
              label: opcMenu.data!.enabled ? "Disable Source" : "Enable Source",
              onClick: () => toggleEnabledMutation.mutate(opcMenu.data!),
            },
            {
              label: "Test Connection",
              onClick: () => handleTestConnection(opcMenu.data!),
            },
            {
              label: "Delete",
              danger: true,
              divider: true,
              onClick: () => {
                if (confirm(`Delete "${opcMenu.data!.name}"?`))
                  deleteMutation.mutate(opcMenu.data!.id);
              },
            },
          ]}
          onClose={closeOpcMenu}
        />
      )}
    </div>
  );
}

