444	                          whiteSpace: "nowrap",
445	                        }}
446	                      >
447	                        :{svc.port}
448	                      </td>
449	                      <td style={{ padding: "10px 12px" }}>
450	                        <StatusBadge status={svc.status} />
451	                      </td>
452	                      <td
453	                        style={{
454	                          padding: "10px 12px",
455	                          color: "var(--io-text-secondary)",
456	                          whiteSpace: "nowrap",
457	                        }}
458	                      >
459	                        {svc.uptime ?? "—"}
460	                      </td>
461	                      <td
462	                        style={{
463	                          padding: "10px 12px",
464	                          color: "var(--io-text-secondary)",
465	                          fontFamily: "var(--io-font-mono, monospace)",
466	                          fontSize: "11px",
467	                          whiteSpace: "nowrap",
