                        }}
                      >
                        {h}
                      </th>
                    ),
                  )}
                </tr>
              </thead>
              <tbody>
                {data.services.map((svc, i) => {
                  const utilPct =
                    svc.pool_size > 0
                      ? ((svc.pool_used / svc.pool_size) * 100).toFixed(0)
                      : "0";
                  const utilColor =
                    Number(utilPct) > 80
                      ? "var(--io-danger)"
                      : Number(utilPct) > 60
                        ? "var(--io-warning)"
                        : "var(--io-success)";
                  return (
                    <tr
                      key={svc.service}
                      style={{
                        background:
                          i % 2 === 0
                            ? "transparent"
                            : "var(--io-surface-secondary)",
                        borderTop: "1px solid var(--io-border)",
                      }}
                    >
                      <td
                        style={{
                          padding: "10px 12px",
                          fontFamily: "var(--io-font-mono, monospace)",
