                      </td>
                      <td
                        style={{
                          padding: "10px 12px",
                          color: utilColor,
                          fontWeight: 700,
                        }}
                      >
                        {utilPct}%
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
