const METRIC_CHARTS: Array<{ metric: string; label: string; unit: string }> = [
  { metric: "io_http_requests_total", label: "HTTP Requests", unit: "req/s" },
  {
    metric: "io_http_request_duration_seconds",
    label: "HTTP Latency",
    unit: "seconds",
  },
  { metric: "io_service_health", label: "Service Health Score", unit: "score" },
  { metric: "io_ws_connections", label: "WS Connections", unit: "connections" },
  {
    metric: "io_opc_updates_received_total",
    label: "OPC Updates",
    unit: "updates/s",
  },
  { metric: "io_db_pool_active", label: "DB Pool Active", unit: "connections" },
];

function MetricChart({
  metric,
  label,
  unit,
  from,
  to,
}: {
  metric: string;
  label: string;
  unit: string;
  from: number;
  to: number;
}) {
  const { data, isLoading } = useQuery({
    queryKey: ["health", "metrics", metric, from, to],
    queryFn: async (): Promise<MetricSample[]> => {
      const r = await api.get<MetricSample[]>(
        `/api/health/metrics?metric=${encodeURIComponent(metric)}&from=${from}&to=${to}`,
      );
      return r.success ? r.data : [];
    },
    refetchInterval: 60_000,
  });

  const containerRef = useRef<HTMLDivElement>(null);

  if (isLoading) {
    return (
      <div
        style={{
          border: "1px solid var(--io-border)",
          borderRadius: "8px",
          padding: "16px",
        }}
      >
        <div
          style={{
            fontSize: "12px",
            fontWeight: 700,
            color: "var(--io-text-primary)",
            marginBottom: "8px",
          }}
        >
          {label}
        </div>
        <div
          style={{
            height: "160px",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            color: "var(--io-text-muted)",
            fontSize: "12px",
          }}
        >
          Loading…
        </div>
      </div>
    );
  }

  const samples = data ?? [];
  const timestamps = samples.map((s) => s.ts);
  const values = samples.map((s) => s.value);

  return (
    <div
      ref={containerRef}
      style={{
        border: "1px solid var(--io-border)",
        borderRadius: "8px",
        padding: "16px",
      }}
    >
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "baseline",
          marginBottom: "10px",
        }}
      >
        <span
          style={{
            fontSize: "12px",
            fontWeight: 700,
            color: "var(--io-text-primary)",
          }}
        >
          {label}
        </span>
        <span style={{ fontSize: "11px", color: "var(--io-text-muted)" }}>
          {unit}
        </span>
      </div>
      <TimeSeriesChart
        timestamps={timestamps}
        series={[{ label, data: values, color: "var(--io-accent)" }]}
        height={160}
      />
    </div>
  );
}

function MetricsTab() {
  const [timeRange, setTimeRange] = useState<TimeRange>("1h");

  const now = Math.floor(Date.now() / 1000);
  const rangeSeconds: Record<TimeRange, number> = {
    "1h": 3600,
    "6h": 21600,
    "24h": 86400,
    "7d": 604800,
    "30d": 2592000,
  };
  const from = now - rangeSeconds[timeRange];
  const to = now;

  return (
    <div>
      {/* Time range selector */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "8px",
          marginBottom: "20px",
        }}
      >
        <span style={{ fontSize: "12px", color: "var(--io-text-muted)" }}>
          Time range:
        </span>
        <div
          style={{
            display: "flex",
            border: "1px solid var(--io-border)",
            borderRadius: "6px",
            overflow: "hidden",
          }}
        >
          {(["1h", "6h", "24h", "7d", "30d"] as TimeRange[]).map((r) => (
            <button
              key={r}
              onClick={() => setTimeRange(r)}
              style={{
                padding: "4px 12px",
                border: "none",
                borderRight:
                  r !== "30d" ? "1px solid var(--io-border)" : "none",
                background:
                  timeRange === r ? "var(--io-accent)" : "transparent",
                color: timeRange === r ? "#fff" : "var(--io-text-secondary)",
                cursor: "pointer",
                fontSize: "12px",
                fontWeight: timeRange === r ? 700 : 400,
              }}
            >
              {TIME_RANGE_LABELS[r]}
            </button>
          ))}
        </div>
      </div>

      {/* Charts grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fill, minmax(380px, 1fr))",
          gap: "16px",
        }}
      >
        {METRIC_CHARTS.map((chart) => (
          <MetricChart
            key={chart.metric}
            metric={chart.metric}
            label={chart.label}
            unit={chart.unit}
            from={from}
            to={to}
          />
        ))}
      </div>

      <p
        style={{
          marginTop: "16px",
          fontSize: "11px",
          color: "var(--io-text-muted)",
        }}
      >
