    oidc: "var(--io-accent)",
    saml: "var(--io-info, #3b82f6)",
    ldap: "var(--io-warning)",
  };
  return (
    <span
      style={{
        display: "inline-block",
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "11px",
        fontWeight: 600,
        background: "var(--io-surface-sunken)",
        color: colors[type] ?? "var(--io-text-secondary)",
        textTransform: "uppercase",
        letterSpacing: "0.04em",
        border: `1px solid ${colors[type] ?? "var(--io-border)"}`,
