interface SetupGuideProps {
  type: "oidc" | "saml" | "ldap";
  ctx: GuideCtx;
}

function SetupGuide({ type, ctx }: SetupGuideProps) {
  const guides =
    type === "oidc" ? OIDC_GUIDES : type === "saml" ? SAML_GUIDES : LDAP_GUIDES;

  const [selectedId, setSelectedId] = useState(guides[0].id);
  const [collapsed, setCollapsed] = useState(false);

  // Reset selection when type changes
  const firstGuideId = guides[0].id;
  useEffect(() => {
    setSelectedId(firstGuideId);
  }, [firstGuideId]);

  const guide = guides.find((g) => g.id === selectedId) ?? guides[0];

  function resolveCode(code: string | ((ctx: GuideCtx) => string) | undefined) {
    if (!code) return null;
    return typeof code === "function" ? code(ctx) : code;
  }

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        height: "100%",
        borderLeft: "1px solid var(--io-border)",
      }}
    >
      {/* Guide header */}
      <div
        style={{
          padding: "16px 16px 12px",
          borderBottom: "1px solid var(--io-border)",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          gap: "8px",
          flexShrink: 0,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
          <span style={{ fontSize: "15px" }}>📋</span>
          <span
            style={{
              fontSize: "13px",
              fontWeight: 600,
              color: "var(--io-text-primary)",
            }}
          >
            Setup Guide
          </span>
        </div>
        <button
          type="button"
          onClick={() => setCollapsed((v) => !v)}
          style={{
            background: "none",
            border: "none",
            color: "var(--io-text-muted)",
            cursor: "pointer",
            fontSize: "14px",
            padding: "2px 4px",
            lineHeight: 1,
          }}
          title={collapsed ? "Expand guide" : "Collapse guide"}
        >
          {collapsed ? "▶" : "◀"}
        </button>
      </div>

      {!collapsed && (
        <>
          {/* IdP selector */}
          <div
            style={{
              padding: "10px 16px",
              borderBottom: "1px solid var(--io-border)",
              flexShrink: 0,
            }}
          >
            <label
              style={{
                ...labelStyle,
                marginBottom: "4px",
                fontSize: "11px",
                textTransform: "uppercase",
                letterSpacing: "0.06em",
              }}
            >
              I'm using:
            </label>
            <select
              value={selectedId}
              onChange={(e) => setSelectedId(e.target.value)}
              style={{
                ...inputStyle,
                fontSize: "12px",
                padding: "5px 8px",
              }}
            >
              {guides.map((g) => (
                <option key={g.id} value={g.id}>
                  {g.label}
                </option>
              ))}
            </select>
          </div>

          {/* Steps */}
          <div
            style={{
              flex: 1,
              overflowY: "auto",
              padding: "12px 16px 20px",
            }}
          >
            {guide.steps.map((step, i) => {
              const code = resolveCode(step.code);
              return (
                <div
                  key={i}
                  style={{
                    marginBottom: "16px",
                    paddingLeft: "28px",
                    position: "relative",
                  }}
                >
                  {/* Step number */}
                  <div
                    style={{
                      position: "absolute",
                      left: 0,
                      top: "2px",
                      width: "20px",
                      height: "20px",
                      borderRadius: "50%",
                      background: "var(--io-accent)",
                      color: "var(--io-text-on-accent, #fff)",
                      fontSize: "11px",
                      fontWeight: 700,
                      display: "flex",
                      alignItems: "center",
