30	function TestEmailDialog({
31	  providerId,
32	  providerName,
33	  onClose,
34	}: {
35	  providerId: string;
36	  providerName: string;
37	  onClose: () => void;
38	}) {
39	  const [toAddress, setToAddress] = useState("");
40	  const [result, setResult] = useState<{
41	    ok: boolean;
42	    message: string;
43	  } | null>(null);
44	
45	  const testMutation = useMutation({
46	    mutationFn: (addr: string) => emailApi.testProvider(providerId, addr),
47	    onSuccess: (res) => {
48	      if (res.success && res.data.ok) {
49	        setResult({ ok: true, message: "Test email sent successfully." });
50	      } else {
51	        setResult({
52	          ok: false,
53	          message: res.success
54	            ? "Provider reported a failure."
55	            : res.error.message,
56	        });
57	      }
58	    },
59	    onError: (e: Error) => setResult({ ok: false, message: e.message }),
60	  });
61	
62	  return (
63	    <Dialog.Root open onOpenChange={(open) => !open && onClose()}>
64	      <Dialog.Portal>
65	        <Dialog.Overlay
66	          style={{
67	            position: "fixed",
68	            inset: 0,
69	            background: "var(--io-modal-backdrop)",
70	            zIndex: 200,
71	          }}
72	        />
73	        <Dialog.Content
74	          aria-describedby={undefined}
75	          style={{
76	            position: "fixed",
77	            top: "50%",
78	            left: "50%",
79	            transform: "translate(-50%, -50%)",
80	            background: "var(--io-surface)",
81	            border: "1px solid var(--io-border)",
82	            borderRadius: "var(--io-radius)",
83	            padding: "24px",
84	            width: "400px",
85	            zIndex: 201,
86	          }}
87	        >
88	          <Dialog.Title
89	            style={{
90	              margin: "0 0 6px",
91	              fontSize: "16px",
92	              fontWeight: 600,
93	              color: "var(--io-text-primary)",
94	            }}
95	          >
96	            Send Test Email
97	          </Dialog.Title>
98	          <p
99	            style={{
100	              margin: "0 0 18px",
101	              fontSize: "13px",
102	              color: "var(--io-text-secondary)",
103	            }}
104	          >
105	            Sends a test message through{" "}
106	            <strong style={{ color: "var(--io-text-primary)" }}>
107	              {providerName}
108	            </strong>{" "}
109	            to verify connectivity and credentials.
110	          </p>
111	
112	          <div>
113	            <label style={labelStyle}>Recipient address</label>
114	            <input
115	              style={inputStyle}
116	              type="email"
117	              value={toAddress}
118	              onChange={(e) => {
119	                setToAddress(e.target.value);
120	                setResult(null);
121	              }}
122	              placeholder="you@example.com"
123	              onKeyDown={(e) => {
124	                if (e.key === "Enter" && toAddress.trim())
125	                  testMutation.mutate(toAddress.trim());
126	              }}
127	              autoFocus
128	            />
129	          </div>
130	
131	          {result && (
132	            <div
133	              style={{
134	                marginTop: "14px",
135	                padding: "10px 12px",
136	                borderRadius: "var(--io-radius)",
137	                background: result.ok
138	                  ? "color-mix(in srgb, var(--io-success) 12%, transparent)"
139	                  : "color-mix(in srgb, var(--io-danger) 12%, transparent)",
140	                border: `1px solid ${result.ok ? "var(--io-success)" : "var(--io-danger)"}`,
141	                color: result.ok ? "var(--io-success)" : "var(--io-danger)",
142	                fontSize: "13px",
143	                fontWeight: 500,
144	              }}
145	            >
146	              {result.ok ? "✓ " : "✗ "}
147	              {result.message}
148	            </div>
149	          )}
150	
151	          <div
152	            style={{
153	              display: "flex",
154	              justifyContent: "flex-end",
155	              gap: "10px",
156	              marginTop: "20px",
157	            }}
158	          >
159	            <button style={btnSecondary} onClick={onClose}>
160	              Close
161	            </button>
