163	              style={btnPrimary}
164	              onClick={() => testMutation.mutate(toAddress.trim())}
165	              disabled={testMutation.isPending || !toAddress.trim()}
166	            >
167	              {testMutation.isPending ? "Sending…" : "Send Test Email"}
168	            </button>
169	          </div>
170	        </Dialog.Content>
171	      </Dialog.Portal>
172	    </Dialog.Root>
173	  );
174	}
