944	function renderStep(text: string) {
945	  const parts = text.split(/`([^`]+)`/);
946	  if (parts.length === 1) return text;
947	  return (
948	    <>
949	      {parts.map((part, i) =>
950	        i % 2 === 0 ? (
951	          part
952	        ) : (
953	          <code
954	            key={i}
955	            style={{
956	              fontFamily: "monospace",
957	              fontSize: "11px",
958	              background:
959	                "color-mix(in srgb, var(--io-accent) 12%, transparent)",
960	              color: "var(--io-accent)",
961	              padding: "1px 5px",
962	              borderRadius: "3px",
963	              whiteSpace: "nowrap",
964	            }}
965	          >
966	            {part}
967	          </code>
968	        ),
969	      )}
970	    </>
971	  );
972	}
