import { ConfirmDialog } from "../../shared/components/ConfirmDialog";
import { SettingsTabs } from "../../shared/components/SettingsTabs";
import { useContextMenu } from "../../shared/hooks/useContextMenu";
import ContextMenu from "../../shared/components/ContextMenu";
import SettingsPageLayout from "./SettingsPageLayout";
import {
  inputStyle,
  labelStyle,
  btnPrimary,
  btnSecondary,
  btnDanger,
  cellStyle,
} from "./settingsStyles";
import {
  emailApi,
  EmailProvider,
  EmailTemplate,
  EmailQueueItem,
  CreateProviderRequest,
  CreateTemplateRequest,
} from "../../api/email";

// ---------------------------------------------------------------------------
// Test email dialog
// ---------------------------------------------------------------------------

function TestEmailDialog({
  providerId,
  providerName,
  onClose,
}: {
  providerId: string;
  providerName: string;
  onClose: () => void;
}) {
  const [toAddress, setToAddress] = useState("");
  const [result, setResult] = useState<{
    ok: boolean;
    message: string;
  } | null>(null);

  const testMutation = useMutation({
    mutationFn: (addr: string) => emailApi.testProvider(providerId, addr),
    onSuccess: (res) => {
      if (res.success && res.data.ok) {
        setResult({ ok: true, message: "Test email sent successfully." });
      } else {
        setResult({
          ok: false,
          message: res.success
            ? "Provider reported a failure."
            : res.error.message,
        });
      }
    },
    onError: (e: Error) => setResult({ ok: false, message: e.message }),
  });

  return (
    <Dialog.Root open onOpenChange={(open) => !open && onClose()}>
      <Dialog.Portal>
        <Dialog.Overlay
          style={{
            position: "fixed",
            inset: 0,
            background: "var(--io-modal-backdrop)",
            zIndex: 200,
          }}
        />
        <Dialog.Content
          aria-describedby={undefined}
          style={{
            position: "fixed",
            top: "50%",
            left: "50%",
            transform: "translate(-50%, -50%)",
            background: "var(--io-surface)",
            border: "1px solid var(--io-border)",
            borderRadius: "var(--io-radius)",
            padding: "24px",
            width: "400px",
            zIndex: 201,
          }}
        >
          <Dialog.Title
            style={{
              margin: "0 0 6px",
              fontSize: "16px",
              fontWeight: 600,
              color: "var(--io-text-primary)",
            }}
          >
            Send Test Email
          </Dialog.Title>
          <p
            style={{
              margin: "0 0 18px",
              fontSize: "13px",
              color: "var(--io-text-secondary)",
            }}
          >
            Sends a test message through{" "}
            <strong style={{ color: "var(--io-text-primary)" }}>
              {providerName}
            </strong>{" "}
            to verify connectivity and credentials.
          </p>

          <div>
            <label style={labelStyle}>Recipient address</label>
            <input
              style={inputStyle}
              type="email"
              value={toAddress}
              onChange={(e) => {
                setToAddress(e.target.value);
                setResult(null);
              }}
              placeholder="you@example.com"
              onKeyDown={(e) => {
                if (e.key === "Enter" && toAddress.trim())
                  testMutation.mutate(toAddress.trim());
              }}
              autoFocus
            />
          </div>

          {result && (
            <div
              style={{
                marginTop: "14px",
                padding: "10px 12px",
                borderRadius: "var(--io-radius)",
                background: result.ok
                  ? "color-mix(in srgb, var(--io-success) 12%, transparent)"
                  : "color-mix(in srgb, var(--io-danger) 12%, transparent)",
                border: `1px solid ${result.ok ? "var(--io-success)" : "var(--io-danger)"}`,
                color: result.ok ? "var(--io-success)" : "var(--io-danger)",
                fontSize: "13px",
                fontWeight: 500,
              }}
            >
              {result.ok ? "✓ " : "✗ "}
              {result.message}
            </div>
          )}

          <div
            style={{
              display: "flex",
              justifyContent: "flex-end",
              gap: "10px",
              marginTop: "20px",
            }}
          >
            <button style={btnSecondary} onClick={onClose}>
              Close
            </button>
            <button
              style={btnPrimary}
              onClick={() => testMutation.mutate(toAddress.trim())}
              disabled={testMutation.isPending || !toAddress.trim()}
            >
              {testMutation.isPending ? "Sending…" : "Send Test Email"}
            </button>
          </div>
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

// ---------------------------------------------------------------------------
// Status badge
// ---------------------------------------------------------------------------

const STATUS_COLORS: Record<string, string> = {
  pending: "var(--io-warning)",
  retry: "var(--io-warning)",
  sent: "var(--io-success)",
  failed: "var(--io-danger)",
};

function StatusBadge({ status }: { status: string }) {
  const color = STATUS_COLORS[status] ?? "var(--io-text-muted)";
  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: "5px",
        fontSize: "12px",
        fontWeight: 500,
        color,
      }}
    >
      <span
        style={{
          width: "7px",
          height: "7px",
          borderRadius: "50%",
          background: color,
          flexShrink: 0,
        }}
      />
      {status}
    </span>
  );
}

// ---------------------------------------------------------------------------
// Providers tab
// ---------------------------------------------------------------------------

function ProvidersTab() {
  const qc = useQueryClient();
  const [showAdd, setShowAdd] = useState(false);
  const [editProvider, setEditProvider] = useState<EmailProvider | null>(null);
  const [testTarget, setTestTarget] = useState<{
    id: string;
    name: string;
  } | null>(null);
  const [deleteConfirm, setDeleteConfirm] = useState<{
    id: string;
    name: string;
  } | null>(null);
  const { menuState, handleContextMenu, closeMenu } =
    useContextMenu<EmailProvider>();

  const { data, isLoading } = useQuery({
    queryKey: ["email-providers"],
    queryFn: async () => {
      const res = await emailApi.listProviders();
      if (!res.success) throw new Error(res.error.message);
      return res.data;
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => emailApi.deleteProvider(id),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["email-providers"] }),
  });

  const providers = data ?? [];

  return (
    <div>
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "16px",
        }}
      >
        <h3
          style={{
            margin: 0,
            fontSize: "15px",
            fontWeight: 600,
            color: "var(--io-text-primary)",
          }}
        >
          Email Providers
        </h3>
        <button style={btnPrimary} onClick={() => setShowAdd(true)}>
          Add Provider
        </button>
      </div>

      {isLoading ? (
        <p style={{ color: "var(--io-text-muted)", fontSize: "13px" }}>
          Loading…
        </p>
      ) : providers.length === 0 ? (
        <p style={{ color: "var(--io-text-muted)", fontSize: "13px" }}>
          No providers configured.
        </p>
      ) : (
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ borderBottom: "1px solid var(--io-border)" }}>
              {[
                "Name",
                "Type",
                "From",
                "Default",
                "Status",
                "Last Test",
                "Actions",
              ].map((h) => (
                <th
                  key={h}
                  style={{
                    ...cellStyle,
                    fontWeight: 600,
                    fontSize: "12px",
                    color: "var(--io-text-muted)",
                    textTransform: "uppercase",
                    letterSpacing: "0.06em",
                    textAlign: "left",
                  }}
                >
                  {h}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {providers.map((p) => (
              <tr
                key={p.id}
                onContextMenu={(e) => handleContextMenu(e, p)}
                style={{
                  borderBottom: "1px solid var(--io-border)",
                  cursor: "context-menu",
                }}
              >
                <td
                  style={{
                    ...cellStyle,
                    fontWeight: 500,
                    color: "var(--io-text-primary)",
                  }}
                >
                  {p.name}
                </td>
                <td style={cellStyle}>{p.provider_type}</td>
                <td style={cellStyle}>
                  {p.from_name
                    ? `${p.from_name} <${p.from_address}>`
                    : p.from_address}
                </td>
                <td style={cellStyle}>{p.is_default ? "✓" : "—"}</td>
                <td style={cellStyle}>
                  <StatusBadge status={p.enabled ? "active" : "disabled"} />
                </td>
                <td style={cellStyle}>
                  {p.last_tested_at ? (
                    p.last_test_ok ? (
                      <span style={{ color: "var(--io-success)" }}>OK</span>
                    ) : (
                      <span style={{ color: "var(--io-danger)" }}>Failed</span>
                    )
                  ) : (
                    "—"
                  )}
                </td>
                <td style={{ ...cellStyle, display: "flex", gap: "8px" }}>
                  <button
                    style={btnSecondary}
                    onClick={() => setTestTarget({ id: p.id, name: p.name })}
                  >
                    Test
                  </button>
                  <button
                    style={btnSecondary}
                    onClick={() => setEditProvider(p)}
                  >
                    Edit
                  </button>
                  <button
                    style={btnDanger}
                    onClick={() => setDeleteConfirm({ id: p.id, name: p.name })}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {menuState?.data && (
        <ContextMenu
          x={menuState.x}
          y={menuState.y}
          items={[
            { label: menuState.data.name, disabled: true },
            {
              label: "Edit",
              permission: "email:configure",
              onClick: () => {
                closeMenu();
                setEditProvider(menuState.data!);
              },
            },
            {
              label: "Test",
              onClick: () => {
                closeMenu();
                setTestTarget({
                  id: menuState.data!.id,
                  name: menuState.data!.name,
                });
              },
            },
            {
              label: "Delete",
              danger: true,
              divider: true,
              permission: "email:configure",
              onClick: () => {
                closeMenu();
                setDeleteConfirm({
                  id: menuState.data!.id,
                  name: menuState.data!.name,
                });
              },
            },
          ]}
          onClose={closeMenu}
        />
      )}

      {(showAdd || editProvider) && (
        <ProviderDialog
          provider={editProvider}
          onClose={() => {
            setShowAdd(false);
            setEditProvider(null);
          }}
        />
      )}

      {testTarget && (
        <TestEmailDialog
          providerId={testTarget.id}
          providerName={testTarget.name}
          onClose={() => {
            setTestTarget(null);
            qc.invalidateQueries({ queryKey: ["email-providers"] });
          }}
        />
      )}

      <ConfirmDialog
        open={!!deleteConfirm}
        onOpenChange={(open) => {
          if (!open) setDeleteConfirm(null);
        }}
        title="Delete Provider"
        description={
          deleteConfirm ? `Delete provider "${deleteConfirm.name}"?` : ""
        }
        confirmLabel="Delete"
        variant="danger"
        onConfirm={() => {
          if (deleteConfirm) deleteMutation.mutate(deleteConfirm.id);
        }}
      />
    </div>
  );
}

