                            ))}
                          </select>
                        ) : f.type === "textarea" ? (
                          <textarea
                            style={{
                              ...inputStyle,
                              height:
                                f.key === "service_account_key"
                                  ? "120px"
                                  : "80px",
                              resize: "vertical",
                              fontFamily: "monospace",
                              fontSize: "12px",
                            }}
                            value={configFields[f.key] ?? ""}
                            onChange={(e) => setField(f.key, e.target.value)}
                            placeholder={f.placeholder}
                          />
                        ) : f.type === "checkbox" ? (
                          <label
                            style={{
                              display: "flex",
                              alignItems: "center",
                              gap: "8px",
                              fontSize: "13px",
                              cursor: "pointer",
                            }}
                          >
                            <input
                              type="checkbox"
                              checked={configFields[f.key] === "true"}
                              onChange={(e) =>
                                setField(
                                  f.key,
                                  e.target.checked ? "true" : "false",
                                )
                              }
                            />
                            {f.label}
                          </label>
                        ) : (
                          <input
                            style={inputStyle}
                            type={
                              f.type === "password"
                                ? "password"
                                : f.type === "number"
                                  ? "number"
                                  : "text"
                            }
                            value={configFields[f.key] ?? ""}
                            onChange={(e) => setField(f.key, e.target.value)}
                            placeholder={
                              isEdit && SECRET_KEYS.has(f.key)
                                ? "Leave blank to keep current value"
