43	function formatDate(iso: string): string {
44	  return new Date(iso).toLocaleDateString(undefined, {
45	    year: "numeric",
46	    month: "short",
47	    day: "numeric",
48	  });
49	}
50	
51	function statusColor(cert: CertInfo): string {
52	  if (cert.is_expired) return "var(--io-danger)";
53	  if (cert.days_remaining < 30) return "var(--io-warning)";
54	  return "var(--io-success)";
55	}
56	
57	function statusLabel(cert: CertInfo): string {
58	  if (cert.is_expired) return "Expired";
59	  if (cert.days_remaining < 30) return "Expires soon";
60	  return "Valid";
61	}
