265	interface UploadModalProps {
266	  onClose: () => void;
267	  onUploaded: () => void;
268	}
269	
270	function UploadModal({ onClose, onUploaded }: UploadModalProps) {
271	  const [name, setName] = useState("");
272	  const [certPem, setCertPem] = useState("");
273	  const [keyPem, setKeyPem] = useState("");
274	  const [error, setError] = useState("");
275	
276	  const uploadMutation = useMutation({
277	    mutationFn: async () => {
278	      const token = getStoredToken();
279	      const API_BASE = import.meta.env.VITE_API_URL ?? "";
280	
281	      const formData = new FormData();
282	      formData.append("name", name.trim());
283	      formData.append(
284	        "cert",
285	        new Blob([certPem], { type: "text/plain" }),
286	        "cert.pem",
287	      );
288	      formData.append(
289	        "key",
290	        new Blob([keyPem], { type: "text/plain" }),
291	        "key.pem",
292	      );
293	
294	      const headers: Record<string, string> = {};
295	      if (token) headers["Authorization"] = `Bearer ${token}`;
296	
297	      const res = await fetch(`${API_BASE}/api/certificates/upload`, {
298	        method: "POST",
299	        headers,
300	        credentials: "include",
301	        body: formData,
302	      });
303	
304	      const json = await res.json();
305	      if (!res.ok) {
306	        throw new Error(
307	          (json as { error?: { message?: string }; message?: string })?.error
308	            ?.message ??
309	            (json as { message?: string })?.message ??
310	            `Upload failed (${res.status})`,
311	        );
312	      }
313	      return json;
314	    },
315	    onSuccess: () => {
316	      onUploaded();
317	    },
318	    onError: (err: Error) => {
319	      setError(err.message);
320	    },
321	  });
322	
323	  const handleSubmit = () => {
324	    setError("");
325	    if (!name.trim()) {
326	      setError("Name is required");
327	      return;
328	    }
329	    if (!certPem.trim()) {
330	      setError("Certificate PEM is required");
331	      return;
332	    }
333	    if (!keyPem.trim()) {
334	      setError("Private Key PEM is required");
335	      return;
336	    }
337	    uploadMutation.mutate();
338	  };
339	
340	  return (
341	    <div
342	      style={{
343	        position: "fixed",
344	        inset: 0,
345	        background: "var(--io-modal-backdrop)",
346	        display: "flex",
347	        alignItems: "center",
348	        justifyContent: "center",
349	        zIndex: 1000,
350	      }}
351	      onClick={(e) => {
352	        if (e.target === e.currentTarget) onClose();
353	      }}
354	    >
355	      <div
356	        role="dialog"
357	        aria-modal="true"
358	        aria-labelledby="upload-cert-title"
359	        style={{
360	          background: "var(--io-surface)",
361	          border: "1px solid var(--io-border)",
362	          borderRadius: "var(--io-radius)",
363	          padding: "24px",
364	          width: "560px",
365	          maxWidth: "calc(100vw - 32px)",
366	          maxHeight: "90vh",
367	          overflowY: "auto",
368	        }}
369	      >
370	        <h3
371	          id="upload-cert-title"
372	          style={{
373	            margin: "0 0 20px",
374	            fontSize: "16px",
375	            fontWeight: 600,
376	            color: "var(--io-text-primary)",
377	          }}
378	        >
379	          Upload Certificate
380	        </h3>
381	
382	        {error && (
383	          <div
384	            style={{
385	              padding: "10px 14px",
386	              borderRadius: "var(--io-radius)",
387	              background: "var(--io-danger-subtle)",
388	              color: "var(--io-danger)",
389	              fontSize: "13px",
390	              marginBottom: "16px",
391	            }}
392	          >
393	            {error}
394	          </div>
395	        )}
396	
397	        <div style={{ marginBottom: "16px" }}>
398	          <label htmlFor="upload-cert-name" style={labelStyle}>
399	            Name *
400	          </label>
401	          <input
402	            id="upload-cert-name"
403	            type="text"
404	            placeholder="e.g. io-tls"
405	            value={name}
406	            onChange={(e) => {
407	              setName(e.target.value);
408	              setError("");
409	            }}
410	            style={inputStyle}
411	          />
412	          <p
413	            style={{
414	              margin: "4px 0 0",
415	              fontSize: "11px",
416	              color: "var(--io-text-muted)",
417	            }}
418	          >
419	            Letters, digits, hyphens, underscores, and dots only.
420	          </p>
421	        </div>
422	
423	        <div style={{ marginBottom: "16px" }}>
424	          <label htmlFor="upload-cert-pem" style={labelStyle}>
425	            Certificate PEM *
426	          </label>
427	          <textarea
428	            id="upload-cert-pem"
429	            placeholder={
430	              "-----BEGIN CERTIFICATE-----\n...\n-----END CERTIFICATE-----"
431	            }
432	            value={certPem}
433	            onChange={(e) => {
434	              setCertPem(e.target.value);
435	              setError("");
436	            }}
437	            rows={6}
438	            style={textareaStyle}
439	          />
440	        </div>
441	
442	        <div style={{ marginBottom: "24px" }}>
443	          <label htmlFor="upload-cert-key" style={labelStyle}>
444	            Private Key PEM *
445	          </label>
446	          <textarea
447	            id="upload-cert-key"
448	            placeholder={
449	              "-----BEGIN PRIVATE KEY-----\n...\n-----END PRIVATE KEY-----"
450	            }
451	            value={keyPem}
452	            onChange={(e) => {
453	              setKeyPem(e.target.value);
454	              setError("");
455	            }}
456	            rows={6}
457	            style={textareaStyle}
458	          />
459	        </div>
460	
461	        <div
462	          style={{ display: "flex", justifyContent: "flex-end", gap: "10px" }}
463	        >
464	          <button onClick={onClose} style={btnSecondary}>
465	            Cancel
466	          </button>
467	          <button
468	            onClick={handleSubmit}
469	            disabled={uploadMutation.isPending}
470	            style={btnPrimary}
471	          >
472	            {uploadMutation.isPending ? "Uploading…" : "Upload Certificate"}
473	          </button>
474	        </div>
475	      </div>
476	    </div>
477	  );
478	}
