import React, { useState } from "react";
import ContextMenu from "../../shared/components/ContextMenu";
import { useContextMenu } from "../../shared/hooks/useContextMenu";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { api, getStoredToken } from "../../api/client";
import type { PaginatedResult } from "../../api/client";
import { ConfirmDialog } from "../../shared/components/ConfirmDialog";
import {
  inputStyle,
  labelStyle,
  btnPrimary,
  btnSecondary,
} from "./settingsStyles";
import { opcCertsApi, OpcServerCert } from "../../api/opcCerts";
import SettingsPageLayout from "./SettingsPageLayout";
import { SettingsTabs } from "../../shared/components/SettingsTabs";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface CertInfo {
  name: string;
  subject: string;
  issuer: string;
  not_before: string;
  not_after: string;
  sans: string[];
  days_remaining: number;
  is_expired: boolean;
  file: string;
}

interface HSTSConfig {
  enabled: boolean;
  max_age: number;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function formatDate(iso: string): string {
  return new Date(iso).toLocaleDateString(undefined, {
    year: "numeric",
    month: "short",
    day: "numeric",
  });
}

function statusColor(cert: CertInfo): string {
  if (cert.is_expired) return "var(--io-danger)";
  if (cert.days_remaining < 30) return "var(--io-warning)";
  return "var(--io-success)";
}

function statusLabel(cert: CertInfo): string {
  if (cert.is_expired) return "Expired";
  if (cert.days_remaining < 30) return "Expires soon";
  return "Valid";
}

// ---------------------------------------------------------------------------
// Shared inline style fragments
// ---------------------------------------------------------------------------

const textareaStyle: React.CSSProperties = {
  width: "100%",
  padding: "8px 12px",
  borderRadius: "var(--io-radius)",
  border: "1px solid var(--io-border)",
  background: "var(--io-surface)",
  color: "var(--io-text-primary)",
  fontSize: "12px",
  fontFamily: "var(--io-font-mono, monospace)",
  resize: "vertical",
  boxSizing: "border-box",
};

const KEY_TYPES = [
  { value: "rsa4096", label: "RSA 4096-bit (recommended)" },
  { value: "rsa2048", label: "RSA 2048-bit" },
  { value: "ecdsa_p256", label: "ECDSA P-256" },
  { value: "ecdsa_p384", label: "ECDSA P-384" },
];

// ---------------------------------------------------------------------------
// Guide panel component
// ---------------------------------------------------------------------------

interface GuideStep {
  title: string;
  detail?: string;
}

interface GuidePanelProps {
  title: string;
  steps: GuideStep[];
  note?: string;
}

function GuidePanel({ title, steps, note }: GuidePanelProps) {
  return (
    <div
      style={{
        background: "var(--io-surface-secondary)",
        border: "1px solid var(--io-border)",
        borderLeft: "3px solid var(--io-accent)",
        borderRadius: "var(--io-radius)",
        padding: "18px 16px",
        overflowY: "auto",
        maxHeight: "calc(90vh - 280px)",
        minHeight: "200px",
      }}
    >
      <div
        style={{
          fontSize: "10px",
          fontWeight: 700,
          color: "var(--io-accent)",
          textTransform: "uppercase",
          letterSpacing: "0.1em",
          marginBottom: "6px",
        }}
      >
        Setup Guide
      </div>
      <div
        style={{
          fontSize: "14px",
          fontWeight: 600,
          color: "var(--io-text-primary)",
          marginBottom: "16px",
          lineHeight: 1.35,
        }}
      >
        {title}
      </div>
      <ol
        style={{
          margin: 0,
          padding: 0,
          listStyle: "none",
          display: "flex",
          flexDirection: "column",
          gap: "12px",
        }}
      >
        {steps.map((step, i) => (
          <li
            key={i}
            style={{ display: "flex", gap: "10px", alignItems: "flex-start" }}
          >
            <span
              style={{
                width: "22px",
                height: "22px",
                borderRadius: "50%",
                background: "var(--io-accent)",
                color: "white",
                fontSize: "11px",
                fontWeight: 700,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                flexShrink: 0,
                marginTop: "1px",
              }}
            >
              {i + 1}
            </span>
            <div>
              <span
                style={{
                  fontSize: "12px",
                  color: "var(--io-text-primary)",
                  lineHeight: 1.5,
                  fontWeight: 500,
                }}
              >
                {step.title}
              </span>
              {step.detail && (
                <div
                  style={{
                    fontSize: "11px",
                    color: "var(--io-text-muted)",
                    marginTop: "3px",
                    lineHeight: 1.45,
                  }}
                >
                  {step.detail}
                </div>
              )}
            </div>
          </li>
        ))}
      </ol>
      {note && (
        <div
          style={{
            marginTop: "16px",
            padding: "10px 12px",
            background:
              "color-mix(in srgb, var(--io-warning) 12%, transparent)",
            border:
              "1px solid color-mix(in srgb, var(--io-warning) 30%, transparent)",
            borderRadius: "var(--io-radius)",
            fontSize: "11px",
            color: "var(--io-text-secondary)",
            lineHeight: 1.5,
          }}
        >
          {note}
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Guide panel toggle button (shared pattern with SMS/Auth providers)
// ---------------------------------------------------------------------------

function GuidePanelToggle({
  show,
  onToggle,
}: {
  show: boolean;
  onToggle: () => void;
}) {
  return (
    <button
      type="button"
      style={{
        background: show
          ? "var(--io-accent)"
          : "color-mix(in srgb, var(--io-accent) 15%, transparent)",
        border: "1px solid var(--io-accent)",
        borderRadius: "var(--io-radius)",
        padding: "5px 14px",
        cursor: "pointer",
        color: show ? "white" : "var(--io-accent)",
        fontSize: "13px",
        fontWeight: 600,
        display: "flex",
        alignItems: "center",
        gap: "6px",
        whiteSpace: "nowrap",
      }}
      onClick={onToggle}
    >
      <span style={{ fontSize: "15px", lineHeight: 1, fontWeight: 800 }}>
        ?
      </span>
      {show ? "Hide Guide" : "Setup Guide"}
    </button>
  );
}

// ---------------------------------------------------------------------------
// Upload modal
// ---------------------------------------------------------------------------

interface UploadModalProps {
  onClose: () => void;
  onUploaded: () => void;
}

function UploadModal({ onClose, onUploaded }: UploadModalProps) {
  const [name, setName] = useState("");
  const [certPem, setCertPem] = useState("");
  const [keyPem, setKeyPem] = useState("");
  const [error, setError] = useState("");

  const uploadMutation = useMutation({
    mutationFn: async () => {
      const token = getStoredToken();
      const API_BASE = import.meta.env.VITE_API_URL ?? "";

      const formData = new FormData();
      formData.append("name", name.trim());
      formData.append(
        "cert",
        new Blob([certPem], { type: "text/plain" }),
        "cert.pem",
      );
      formData.append(
        "key",
        new Blob([keyPem], { type: "text/plain" }),
        "key.pem",
      );

      const headers: Record<string, string> = {};
      if (token) headers["Authorization"] = `Bearer ${token}`;

      const res = await fetch(`${API_BASE}/api/certificates/upload`, {
        method: "POST",
        headers,
        credentials: "include",
        body: formData,
      });

      const json = await res.json();
      if (!res.ok) {
        throw new Error(
          (json as { error?: { message?: string }; message?: string })?.error
            ?.message ??
            (json as { message?: string })?.message ??
            `Upload failed (${res.status})`,
        );
      }
      return json;
    },
    onSuccess: () => {
      onUploaded();
    },
    onError: (err: Error) => {
      setError(err.message);
    },
  });

  const handleSubmit = () => {
    setError("");
    if (!name.trim()) {
      setError("Name is required");
      return;
    }
    if (!certPem.trim()) {
      setError("Certificate PEM is required");
      return;
    }
    if (!keyPem.trim()) {
      setError("Private Key PEM is required");
      return;
    }
    uploadMutation.mutate();
  };

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "var(--io-modal-backdrop)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 1000,
      }}
      onClick={(e) => {
        if (e.target === e.currentTarget) onClose();
      }}
    >
      <div
        role="dialog"
        aria-modal="true"
        aria-labelledby="upload-cert-title"
        style={{
          background: "var(--io-surface)",
          border: "1px solid var(--io-border)",
          borderRadius: "var(--io-radius)",
          padding: "24px",
          width: "560px",
          maxWidth: "calc(100vw - 32px)",
          maxHeight: "90vh",
          overflowY: "auto",
        }}
      >
        <h3
          id="upload-cert-title"
          style={{
            margin: "0 0 20px",
            fontSize: "16px",
            fontWeight: 600,
            color: "var(--io-text-primary)",
          }}
        >
          Upload Certificate
        </h3>

        {error && (
          <div
            style={{
              padding: "10px 14px",
              borderRadius: "var(--io-radius)",
              background: "var(--io-danger-subtle)",
              color: "var(--io-danger)",
              fontSize: "13px",
              marginBottom: "16px",
            }}
          >
            {error}
          </div>
        )}

        <div style={{ marginBottom: "16px" }}>
          <label htmlFor="upload-cert-name" style={labelStyle}>
            Name *
          </label>
          <input
            id="upload-cert-name"
            type="text"
            placeholder="e.g. io-tls"
            value={name}
            onChange={(e) => {
              setName(e.target.value);
              setError("");
            }}
            style={inputStyle}
          />
          <p
            style={{
              margin: "4px 0 0",
              fontSize: "11px",
              color: "var(--io-text-muted)",
            }}
          >
            Letters, digits, hyphens, underscores, and dots only.
          </p>
        </div>

        <div style={{ marginBottom: "16px" }}>
          <label htmlFor="upload-cert-pem" style={labelStyle}>
            Certificate PEM *
          </label>
          <textarea
            id="upload-cert-pem"
            placeholder={
              "-----BEGIN CERTIFICATE-----\n...\n-----END CERTIFICATE-----"
            }
            value={certPem}
            onChange={(e) => {
              setCertPem(e.target.value);
              setError("");
            }}
            rows={6}
            style={textareaStyle}
          />
        </div>

        <div style={{ marginBottom: "24px" }}>
          <label htmlFor="upload-cert-key" style={labelStyle}>
            Private Key PEM *
          </label>
          <textarea
            id="upload-cert-key"
            placeholder={
              "-----BEGIN PRIVATE KEY-----\n...\n-----END PRIVATE KEY-----"
            }
            value={keyPem}
            onChange={(e) => {
              setKeyPem(e.target.value);
              setError("");
            }}
            rows={6}
            style={textareaStyle}
          />
        </div>

        <div
          style={{ display: "flex", justifyContent: "flex-end", gap: "10px" }}
        >
          <button onClick={onClose} style={btnSecondary}>
            Cancel
          </button>
          <button
            onClick={handleSubmit}
            disabled={uploadMutation.isPending}
            style={btnPrimary}
          >
            {uploadMutation.isPending ? "Uploading…" : "Upload Certificate"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Installed Certificates tab
// ---------------------------------------------------------------------------

function InstalledTab() {
  const queryClient = useQueryClient();
  const [showUpload, setShowUpload] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);
  const {
    menuState: certMenu,
    handleContextMenu: openCertMenu,
    closeMenu: closeCertMenu,
  } = useContextMenu<CertInfo>();
  const [certDetail, setCertDetail] = useState<CertInfo | null>(null);

  const { data, isLoading, isError } = useQuery({
    queryKey: ["certificates"],
    queryFn: () => api.get<PaginatedResult<CertInfo>>("/api/certificates"),
  });

  const rawData = data?.success ? data.data : null;
  const certs: CertInfo[] = Array.isArray(rawData?.data) ? rawData.data : [];

  const deleteMutation = useMutation({
    mutationFn: (name: string) =>
      api.delete(`/api/certificates/${encodeURIComponent(name)}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["certificates"] });
    },
  });

  const handleUploaded = () => {
    setShowUpload(false);
    queryClient.invalidateQueries({ queryKey: ["certificates"] });
  };

  return (
    <div>
      <div
        style={{
          display: "flex",
          justifyContent: "flex-end",
          marginBottom: "16px",
        }}
      >
        <button onClick={() => setShowUpload(true)} style={btnPrimary}>
          + Upload Certificate
        </button>
      </div>

      {isLoading ? (
        <div style={{ color: "var(--io-text-muted)", fontSize: "13px" }}>
          Loading…
        </div>
      ) : isError ? (
        <div
          style={{
            padding: "16px",
            borderRadius: "var(--io-radius)",
            background: "var(--io-danger-subtle)",
            color: "var(--io-danger)",
            fontSize: "13px",
          }}
        >
          Failed to load certificates. Check that the api-gateway is reachable.
        </div>
      ) : certs.length === 0 ? (
        <div
          style={{
            padding: "32px",
            textAlign: "center",
            border: "1px dashed var(--io-border)",
            borderRadius: "var(--io-radius)",
            color: "var(--io-text-muted)",
            fontSize: "13px",
          }}
        >
          No certificates installed. Upload a certificate or use the Provision
          tab to generate one.
        </div>
      ) : (
        <div
          style={{
            border: "1px solid var(--io-border)",
            borderRadius: "var(--io-radius)",
            overflow: "hidden",
          }}
        >
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr
                style={{
                  background: "var(--io-surface-secondary)",
                  borderBottom: "1px solid var(--io-border)",
                }}
              >
                {[
                  "Name",
                  "Subject",
                  "Issuer",
                  "Expiry",
                  "Days Remaining",
                  "Status",
                  "",
                ].map((h) => (
                  <th
                    key={h}
                    style={{
                      padding: "10px 14px",
                      textAlign: "left",
                      fontSize: "11px",
                      fontWeight: 600,
                      color: "var(--io-text-muted)",
                      textTransform: "uppercase",
                      letterSpacing: "0.06em",
                      whiteSpace: "nowrap",
                    }}
                  >
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {certs.map((cert) => (
                <tr
                  key={cert.name}
                  style={{
                    borderBottom:
                      "1px solid var(--io-border-subtle, var(--io-border))",
                  }}
                  onContextMenu={(e) => openCertMenu(e, cert)}
                >
                  <td
                    style={{
                      padding: "12px 14px",
                      fontSize: "13px",
                      color: "var(--io-text-primary)",
                      fontWeight: 500,
                      whiteSpace: "nowrap",
                    }}
                  >
                    {cert.name}
                  </td>
                  <td
                    style={{
                      padding: "12px 14px",
                      fontSize: "12px",
                      color: "var(--io-text-secondary)",
                      maxWidth: "200px",
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                      whiteSpace: "nowrap",
                    }}
                    title={cert.subject}
                  >
                    {cert.subject}
                  </td>
                  <td
                    style={{
                      padding: "12px 14px",
                      fontSize: "12px",
                      color: "var(--io-text-muted)",
                      maxWidth: "180px",
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                      whiteSpace: "nowrap",
                    }}
                    title={cert.issuer}
                  >
                    {cert.issuer}
                  </td>
                  <td
                    style={{
                      padding: "12px 14px",
                      fontSize: "12px",
                      color: "var(--io-text-secondary)",
                      whiteSpace: "nowrap",
                    }}
                  >
                    {formatDate(cert.not_after)}
                  </td>
                  <td
                    style={{
                      padding: "12px 14px",
                      fontSize: "12px",
                      color: statusColor(cert),
                      fontWeight: 600,
                      whiteSpace: "nowrap",
                    }}
                  >
                    {cert.is_expired ? "Expired" : `${cert.days_remaining}d`}
                  </td>
                  <td style={{ padding: "12px 14px" }}>
                    <span
                      style={{
                        display: "inline-block",
                        padding: "2px 10px",
                        borderRadius: "99px",
                        background: `color-mix(in srgb, ${statusColor(cert)} 12%, transparent)`,
                        color: statusColor(cert),
                        fontSize: "11px",
                        fontWeight: 600,
                      }}
                    >
                      {statusLabel(cert)}
                    </span>
                  </td>
                  <td style={{ padding: "12px 14px", whiteSpace: "nowrap" }}>
                    <button
                      onClick={() => setCertDetail(cert)}
                      style={{
                        ...btnSecondary,
                        padding: "4px 10px",
                        fontSize: "12px",
                        marginRight: "6px",
                      }}
                    >
                      Details
                    </button>
                    <button
                      onClick={() => setDeleteConfirm(cert.name)}
                      style={{
                        padding: "4px 10px",
                        fontSize: "12px",
                        borderRadius: "var(--io-radius)",
                        border: "1px solid var(--io-danger)",
                        background: "transparent",
                        color: "var(--io-danger)",
                        cursor: "pointer",
                      }}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* SANs detail strip */}
      {certs.some((c) => c.sans.length > 0) && (
        <div style={{ marginTop: "16px" }}>
          {certs
            .filter((c) => c.sans.length > 0)
            .map((cert) => (
              <div
                key={`${cert.name}-sans`}
                style={{
                  marginBottom: "8px",
                  padding: "10px 14px",
                  background: "var(--io-surface-secondary)",
                  borderRadius: "var(--io-radius)",
                  border: "1px solid var(--io-border-subtle, var(--io-border))",
                  fontSize: "12px",
                  color: "var(--io-text-secondary)",
                }}
              >
                <strong style={{ color: "var(--io-text-primary)" }}>
                  {cert.name}
                </strong>
                {" — SANs: "}
                {cert.sans.join(", ")}
              </div>
            ))}
        </div>
      )}

      <OpcServerCertsSection />

      {showUpload && (
        <UploadModal
          onClose={() => setShowUpload(false)}
          onUploaded={handleUploaded}
        />
      )}

      {certMenu && (
        <ContextMenu
          x={certMenu.x}
          y={certMenu.y}
          items={[
            {
              label: "View Details",
              onClick: () => setCertDetail(certMenu.data!),
            },
            {
              label: "Download Certificate",
              onClick: () => {
                const base = import.meta.env.VITE_API_URL ?? "";
                window.location.href = `${base}/api/certificates/${encodeURIComponent(certMenu.data!.name)}/download`;
              },
            },
            {
              label: "Copy Fingerprint",
              onClick: () => {
                navigator.clipboard
                  .writeText(certMenu.data!.subject)
                  .catch(() => {});
              },
            },
          ]}
          onClose={closeCertMenu}
        />
      )}

      {certDetail && (
        <div
          style={{
            position: "fixed",
            inset: 0,
            background: "var(--io-modal-backdrop)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 2000,
          }}
          onClick={() => setCertDetail(null)}
        >
          <div
            role="dialog"
            aria-modal="true"
            aria-labelledby="cert-detail-title"
            style={{
              background: "var(--io-surface-elevated)",
              border: "1px solid var(--io-border)",
              borderRadius: "var(--io-radius)",
              padding: "24px",
              width: "480px",
              maxWidth: "calc(100vw - 32px)",
              maxHeight: "80vh",
              overflowY: "auto",
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
                marginBottom: "20px",
              }}
            >
              <h3
                id="cert-detail-title"
                style={{
                  margin: 0,
                  fontSize: "16px",
                  fontWeight: 600,
                  color: "var(--io-text-primary)",
                }}
              >
                Certificate Details
              </h3>
              <button
                aria-label="Close"
                onClick={() => setCertDetail(null)}
                style={{
                  background: "none",
                  border: "none",
                  color: "var(--io-text-muted)",
                  cursor: "pointer",
                  fontSize: "18px",
                  lineHeight: 1,
                }}
              >
                ×
              </button>
            </div>
            <dl
              style={{
                margin: 0,
                display: "flex",
                flexDirection: "column",
                gap: "10px",
              }}
            >
              {[
                ["Name", certDetail.name],
                ["Subject", certDetail.subject],
                ["Issuer", certDetail.issuer],
                ["Valid From", formatDate(certDetail.not_before)],
                ["Valid Until", formatDate(certDetail.not_after)],
                ["Status", statusLabel(certDetail)],
                [
                  "Days Remaining",
                  certDetail.is_expired
                    ? "Expired"
                    : `${certDetail.days_remaining} days`,
                ],
                ...(certDetail.sans.length > 0
                  ? [["SANs", certDetail.sans.join(", ")]]
                  : []),
              ].map(([label, value]) => (
                <div key={label} style={{ display: "flex", gap: "12px" }}>
                  <dt
                    style={{
                      fontSize: "12px",
                      fontWeight: 600,
                      color: "var(--io-text-muted)",
                      width: "120px",
                      flexShrink: 0,
                      textTransform: "uppercase",
                      letterSpacing: "0.05em",
                    }}
                  >
                    {label}
                  </dt>
                  <dd
                    style={{
                      margin: 0,
                      fontSize: "13px",
                      color: "var(--io-text-primary)",
                      wordBreak: "break-all",
                    }}
                  >
                    {value}
                  </dd>
                </div>
              ))}
            </dl>
            <div
              style={{
                display: "flex",
                justifyContent: "flex-end",
                marginTop: "20px",
              }}
            >
              <button onClick={() => setCertDetail(null)} style={btnSecondary}>
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      <ConfirmDialog
        open={!!deleteConfirm}
        onOpenChange={(open) => {
          if (!open) setDeleteConfirm(null);
        }}
        title="Delete Certificate"
        description={
          deleteConfirm
            ? `Delete certificate "${deleteConfirm}"? This cannot be undone.`
            : ""
        }
        confirmLabel="Delete"
        variant="danger"
        onConfirm={() => {
          if (deleteConfirm) deleteMutation.mutate(deleteConfirm);
        }}
      />
    </div>
  );
}

