          padding: "20px",
          display: "grid",
          gridTemplateColumns: showGuide ? "1fr 360px" : "1fr",
          gap: "24px",
          alignItems: "start",
        }}
      >
        <div style={{ display: "flex", flexDirection: "column", gap: "14px" }}>
          {result && (
            <div
              style={{
                padding: "10px 14px",
                borderRadius: "var(--io-radius)",
                background: "var(--io-danger-subtle)",
                color: "var(--io-danger)",
                fontSize: "13px",
              }}
            >
              {result.message}
            </div>
          )}

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(3, 1fr)",
              gap: "14px",
            }}
          >
            <div style={{ gridColumn: "span 2" }}>
              <label style={labelStyle}>Common Name (CN) *</label>
              <input
                style={inputStyle}
                value={cn}
                onChange={(e) => setCn(e.target.value)}
                placeholder="io.corp.example.com"
              />
            </div>
            <div>
              <label style={labelStyle}>Country (C)</label>
              <input
                style={inputStyle}
                value={country}
                onChange={(e) => setCountry(e.target.value)}
                placeholder="US"
                maxLength={2}
              />
            </div>
          </div>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "14px",
            }}
          >
            <div>
              <label style={labelStyle}>Organization (O)</label>
              <input
                style={inputStyle}
                value={org}
                onChange={(e) => setOrg(e.target.value)}
                placeholder="Acme Corp"
              />
            </div>
            <div>
              <label style={labelStyle}>Organizational Unit (OU)</label>
              <input
                style={inputStyle}
                value={ou}
                onChange={(e) => setOu(e.target.value)}
                placeholder="IT Operations"
              />
            </div>
          </div>

          <div>
            <label style={labelStyle}>Subject Alternative Names (SANs)</label>
            <textarea
              style={{
                ...textareaStyle,
                fontFamily: "var(--io-font-mono, monospace)",
              }}
