interface ProviderRowProps {
  provider: AuthProviderConfig;
}

function ProviderRow({ provider }: ProviderRowProps) {
  const qc = useQueryClient();
  const [expanded, setExpanded] = useState(false);
  const [editOpen, setEditOpen] = useState(false);
  const [confirmDeleteOpen, setConfirmDeleteOpen] = useState(false);
  const [testStatus, setTestStatus] = useState<{
    ok: boolean;
    message: string;
  } | null>(null);
  const [testing, setTesting] = useState(false);

  const deleteMutation = useMutation({
    mutationFn: () => authProvidersApi.delete(provider.id),
    onSuccess: () => qc.invalidateQueries({ queryKey: ["auth-providers"] }),
  });

  const { menuState, handleContextMenu, closeMenu } =
    useContextMenu<AuthProviderConfig>();

  const handleTest = async () => {
    setTesting(true);
    setTestStatus(null);
    try {
      const result = await api.post<{ message: string }>(
        `/api/auth/admin/providers/${provider.id}/test`,
        {},
      );
      if (result.success) {
        setTestStatus({
          ok: true,
          message:
            (result.data as { message?: string }).message ??
            "Connection successful",
        });
      } else {
        const err = result as { success: false; error?: { message: string } };
        setTestStatus({
          ok: false,
          message: err.error?.message ?? "Test failed",
        });
      }
    } catch {
      setTestStatus({ ok: false, message: "Connection test failed" });
    } finally {
      setTesting(false);
    }
  };

  return (
    <>
      <tr
        style={{
          borderBottom: "1px solid var(--io-border)",
          cursor: "context-menu",
        }}
        onContextMenu={(e) => handleContextMenu(e, provider)}
      >
        <td style={cellStyle}>
          <div style={{ fontWeight: 500, color: "var(--io-text-primary)" }}>
            {provider.display_name}
          </div>
          <div
            style={{
              fontSize: "11px",
              color: "var(--io-text-muted)",
              fontFamily: "var(--io-font-mono, monospace)",
            }}
          >
            {provider.name}
          </div>
        </td>
        <td style={cellStyle}>
          <TypeBadge type={provider.provider_type} />
        </td>
        <td style={cellStyle}>
          <span
            style={{
              fontSize: "12px",
              fontWeight: 600,
              color: provider.enabled
                ? "var(--io-success)"
                : "var(--io-text-muted)",
            }}
          >
            {provider.enabled ? "Enabled" : "Disabled"}
          </span>
          {provider.jit_provisioning && (
            <span
              style={{
                marginLeft: "8px",
                fontSize: "10px",
                padding: "1px 5px",
                borderRadius: "999px",
                background: "var(--io-surface-sunken)",
                color: "var(--io-text-muted)",
                border: "1px solid var(--io-border)",
              }}
            >
              JIT
            </span>
          )}
        </td>
        <td style={{ ...cellStyle, textAlign: "right" }}>
          <div
            style={{
              display: "flex",
              gap: "6px",
              justifyContent: "flex-end",
              alignItems: "center",
            }}
          >
            {testStatus && (
              <span
                style={{
                  fontSize: "12px",
                  color: testStatus.ok
                    ? "var(--io-success)"
                    : "var(--io-danger)",
                  maxWidth: "200px",
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                  whiteSpace: "nowrap",
                }}
              >
                {testStatus.message}
              </span>
            )}
            <button style={btnSmall} disabled={testing} onClick={handleTest}>
              {testing ? "Testing…" : "Test"}
            </button>
            <button style={btnSmall} onClick={() => setExpanded((v) => !v)}>
              {expanded ? "Hide Mappings" : "Mappings"}
            </button>
            <button style={btnSmall} onClick={() => setEditOpen(true)}>
              Edit
            </button>
            <button
              style={{
                ...btnSmall,
                color: "var(--io-danger)",
                borderColor: "var(--io-danger)",
              }}
              disabled={deleteMutation.isPending}
              onClick={() => setConfirmDeleteOpen(true)}
            >
              Delete
            </button>
          </div>
        </td>
      </tr>

      {menuState?.data && (
        <ContextMenu
          x={menuState.x}
          y={menuState.y}
          items={[
            { label: menuState.data.display_name, disabled: true },
            {
              label: "Edit / View Mappings",
              onClick: () => {
                closeMenu();
                setExpanded((v) => !v);
              },
            },
            {
              label: "Test Connection",
              onClick: () => {
                closeMenu();
                void handleTest();
              },
            },
            {
              label: "Delete",
              danger: true,
              divider: true,
              permission: "auth:configure",
              onClick: () => {
                closeMenu();
                setConfirmDeleteOpen(true);
              },
            },
          ]}
          onClose={closeMenu}
        />
      )}

      {expanded && (
        <tr>
          <td colSpan={4} style={{ padding: "0 14px 14px" }}>
            <RoleMappings provider={provider} />
          </td>
        </tr>
      )}

      <ProviderDialog
        open={editOpen}
        onOpenChange={setEditOpen}
        existing={provider}
      />

      <ConfirmDialog
        open={confirmDeleteOpen}
        onOpenChange={setConfirmDeleteOpen}
        title={`Delete "${provider.display_name}"?`}
        description="This auth provider will be permanently removed. Users who sign in via this provider will no longer be able to authenticate."
        confirmLabel="Delete"
        variant="danger"
        onConfirm={() => deleteMutation.mutate()}
      />
    </>
  );
}

