function TemplateField({
  field,
  value,
  onChange,
}: {
  field: TemplateFieldDef;
  value: string;
  onChange: (val: string) => void;
}) {
  if (field.type === "secret") {
    return (
      <input
        type="password"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={field.placeholder ?? ""}
        autoComplete="new-password"
        style={inputStyle}
      />
    );
  }
  if (field.type === "number") {
    return (
      <input
        type="number"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={field.placeholder ?? ""}
        style={inputStyle}
      />
    );
  }
  if (field.type === "textarea") {
    return (
      <textarea
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={field.placeholder ?? ""}
        rows={4}
        style={{ ...inputStyle, resize: "vertical", fontFamily: "monospace" }}
      />
    );
  }
  if (field.type === "select" && field.options) {
    return (
      <select
        value={value}
        onChange={(e) => onChange(e.target.value)}
        style={inputStyle}
      >
        <option value="">Select...</option>
        {field.options.map((opt) => (
          <option key={opt.value} value={opt.value}>
            {opt.label}
          </option>
        ))}
      </select>
    );
  }
  // Default: text
  return (
    <input
      type="text"
      value={value}
      onChange={(e) => onChange(e.target.value)}
      placeholder={field.placeholder ?? ""}
      style={inputStyle}
    />
  );
}

function SetupConnectionDrawerContent({
  template,
  onClose,
}: {
  template: ConnectorTemplate;
  onClose: () => void;
}) {
  const queryClient = useQueryClient();
  const [name, setName] = useState(`${template.name} Connection`);
  const [fieldValues, setFieldValues] = useState<Record<string, string>>(() =>
    Object.fromEntries(
      (template.required_fields ?? []).map((f) => [f.key, ""]),
    ),
  );
  const [error, setError] = useState<string | null>(null);

  const hasRequiredFields =
    Array.isArray(template.required_fields) &&
    template.required_fields.length > 0;

  const mutation = useMutation({
    mutationFn: (body: InstantiateTemplateBody) =>
      importApi.instantiateTemplate(template.slug, body),
    onSuccess: (res) => {
      if (res.success) {
        queryClient.invalidateQueries({ queryKey: ["import-connections"] });
        onClose();
      } else {
        setError(res.error.message);
      }
    },
  });

  const handleSave = () => {
    setError(null);
    mutation.mutate({
      field_values: fieldValues,
      connection_name: name,
    });
  };

  const setField = (key: string, val: string) => {
    setFieldValues((prev) => ({ ...prev, [key]: val }));
  };

  return (
    <div>
      <div style={{ marginBottom: "20px" }}>
        <DomainBadge domain={template.domain} />
        <span
          style={{
            marginLeft: "8px",
            color: "var(--io-text-muted)",
            fontSize: "13px",
          }}
        >
          {template.vendor}
        </span>
      </div>
      {template.description && (
        <p
          style={{
            fontSize: "13px",
            color: "var(--io-text-secondary)",
            marginBottom: "24px",
            lineHeight: 1.5,
          }}
        >
          {template.description}
        </p>
      )}

      <Field label="Connection Name">
        <input
          type="text"
          value={name}
          onChange={(e) => setName(e.target.value)}
          style={inputStyle}
        />
      </Field>

      {hasRequiredFields
        ? template.required_fields.map((field) => (
            <Field key={field.key} label={field.label}>
              <TemplateField
                field={field}
                value={fieldValues[field.key] ?? ""}
                onChange={(val) => setField(field.key, val)}
              />
            </Field>
          ))
        : null}

      {error && (
        <div
          style={{
            padding: "10px 12px",
            background: "var(--io-danger-subtle)",
            color: "var(--io-danger)",
            borderRadius: "var(--io-radius)",
            fontSize: "13px",
            marginBottom: "16px",
          }}
        >
          {error}
        </div>
      )}

      <div style={{ display: "flex", gap: "8px", justifyContent: "flex-end" }}>
        <button onClick={onClose} style={secondaryBtnStyle}>
          Cancel
        </button>
        <button
          onClick={handleSave}
          disabled={mutation.isPending || !name.trim()}
          style={primaryBtnStyle}
        >
          {mutation.isPending ? "Saving..." : "Save Connection"}
        </button>
      </div>
    </div>
  );
}

