function ConnectionsTab() {
  const queryClient = useQueryClient();
  const [wizardOpen, setWizardOpen] = useState(false);
  const [editConn, setEditConn] = useState<ImportConnection | null>(null);
  const canManageConnections = usePermission("system:import_connections");
  const {
    menuState: connMenu,
    handleContextMenu: openConnMenu,
    closeMenu: closeConnMenu,
  } = useContextMenu<ImportConnection>();

  const { data, isLoading } = useQuery({
    queryKey: ["import-connections"],
    queryFn: async () => {
      const res = await importApi.listConnections();
      return res.success ? res.data : [];
    },
  });

  const connections = data ?? [];

  // Fetch definitions to determine per-connection definition count for Delete graying.
  // Shares the same cache key as DefinitionsTab — no duplicate network request.
  const { data: defsData } = useQuery({
    queryKey: ["import-definitions"],
    queryFn: async () => {
      const res = await importApi.listDefinitions();
      return res.success ? res.data : [];
    },
    staleTime: 30_000,
  });
  const definitions = defsData ?? [];

  function definitionCountForConnection(connectionId: string): number {
    return definitions.filter((d) => d.connection_id === connectionId).length;
  }

  const deleteMutation = useMutation({
    mutationFn: (id: string) => importApi.deleteConnection(id),
    onSuccess: () =>
      queryClient.invalidateQueries({ queryKey: ["import-connections"] }),
  });

  const testMutation = useMutation({
    mutationFn: (id: string) => importApi.testConnection(id),
    onSuccess: (res) => {
      queryClient.invalidateQueries({ queryKey: ["import-connections"] });
      if (!res.success) {
        showToast({
          title: "Connection test failed",
          description: res.error.message,
          variant: "error",
        });
      }
    },
    onError: () =>
      showToast({
        title: "Connection test failed",
        description: "Network error",
        variant: "error",
      }),
  });

  const toggleConnMutation = useMutation({
    mutationFn: ({ id, enabled }: { id: string; enabled: boolean }) =>
      importApi.updateConnection(id, { enabled }),
    onSuccess: () =>
      queryClient.invalidateQueries({ queryKey: ["import-connections"] }),
  });

  if (isLoading) {
    return (
      <div
        style={{
          color: "var(--io-text-muted)",
          textAlign: "center",
          padding: "40px",
        }}
      >
        Loading connections...
      </div>
    );
  }

  return (
    <div>
      <div
        style={{
          display: "flex",
          justifyContent: "flex-end",
          marginBottom: "16px",
        }}
      >
        {canManageConnections && (
          <button onClick={() => setWizardOpen(true)} style={primaryBtnStyle}>
            + New Connection
          </button>
        )}
      </div>

      {connections.length === 0 ? (
        <div
          style={{
            textAlign: "center",
            padding: "48px",
            color: "var(--io-text-muted)",
            background: "var(--io-surface-secondary)",
            borderRadius: "var(--io-radius)",
            border: "1px solid var(--io-border)",
          }}
        >
          No connections configured yet. Click "New Connection" to add one.
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
          {connections.map((conn) => (
            <div
              key={conn.id}
              style={{
                background: "var(--io-surface-secondary)",
                border: "1px solid var(--io-border)",
                borderRadius: "var(--io-radius)",
                padding: "14px 16px",
                display: "flex",
                alignItems: "center",
                gap: "12px",
              }}
              onContextMenu={(e) => openConnMenu(e, conn)}
            >
              <div style={{ flex: 1 }}>
                <div
                  style={{
                    fontWeight: 600,
                    fontSize: "14px",
                    marginBottom: "4px",
                  }}
                >
                  {conn.name}
                </div>
                <div
                  style={{
                    fontSize: "12px",
                    color: "var(--io-text-muted)",
                    display: "flex",
                    gap: "12px",
                  }}
                >
                  <span>{conn.connection_type}</span>
                  <span>Auth: {conn.auth_type}</span>
                  {conn.last_tested_at && (
                    <span>Tested: {formatDate(conn.last_tested_at)}</span>
                  )}
                </div>
              </div>
              <div
                style={{ display: "flex", alignItems: "center", gap: "8px" }}
              >
                {conn.last_test_status ? (
                  <StatusBadge status={conn.last_test_status} />
                ) : (
                  <StatusBadge status="untested" />
                )}
                {canManageConnections && (
                  <>
                    <button
                      onClick={() => testMutation.mutate(conn.id)}
                      disabled={testMutation.isPending}
                      style={secondaryBtnStyle}
                      title="Test connection"
                    >
                      Test
                    </button>
                    <button
                      onClick={() => setEditConn(conn)}
                      style={secondaryBtnStyle}
                      title="Edit connection"
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => {
                        if (confirm(`Delete connection "${conn.name}"?`)) {
                          deleteMutation.mutate(conn.id);
                        }
                      }}
                      style={dangerBtnStyle}
                      title="Delete connection"
                    >
                      Delete
                    </button>
                  </>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      <Modal
        title="New Connection"
        open={wizardOpen}
        onClose={() => setWizardOpen(false)}
      >
        <NewConnectionWizard onClose={() => setWizardOpen(false)} />
      </Modal>

      <Modal
        title={editConn ? `Edit: ${editConn.name}` : "Edit Connection"}
        open={!!editConn}
        onClose={() => setEditConn(null)}
      >
        {editConn && (
          <EditConnectionForm
            conn={editConn}
            onClose={() => setEditConn(null)}
          />
        )}
      </Modal>

      {connMenu && (
        <ContextMenu
          x={connMenu.x}
          y={connMenu.y}
          items={[
            {
              label: "Test Connection",
              onClick: () => testMutation.mutate(connMenu.data!.id),
            },
            {
              label: connMenu.data!.enabled ? "Disable" : "Enable",
              onClick: () =>
                toggleConnMutation.mutate({
                  id: connMenu.data!.id,
                  enabled: !connMenu.data!.enabled,
                }),
            },
            {
              label: "Delete",
              danger: true,
              divider: true,
              disabled: definitionCountForConnection(connMenu.data!.id) > 0,
              onClick: () => {
                if (confirm(`Delete connection "${connMenu.data!.name}"?`)) {
                  deleteMutation.mutate(connMenu.data!.id);
                }
              },
            },
          ]}
          onClose={closeConnMenu}
        />
      )}
    </div>
  );
}

function NewConnectionWizard({ onClose }: { onClose: () => void }) {
  const queryClient = useQueryClient();
  const [step, setStep] = useState(1);
  const [selectedTemplate, setSelectedTemplate] =
    useState<ConnectorTemplate | null>(null);
  const [name, setName] = useState("");
  const [authType, setAuthType] = useState("none");
  const [configJson, setConfigJson] = useState("{}");
  const [authConfigJson, setAuthConfigJson] = useState("{}");
  const [dataCategoryId, setDataCategoryId] = useState<string>("");
  const [testResult, setTestResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [savedId, setSavedId] = useState<string | null>(null);
  const catQuery = useDataCategories();
  const categories = catQuery.data ?? [];

  const { data } = useQuery({
    queryKey: ["connector-templates"],
    queryFn: async () => {
      const res = await importApi.listTemplates();
      return res.success ? res.data : [];
    },
  });

  const templates = data ?? [];

  const saveMutation = useMutation({
    mutationFn: (body: CreateConnectionBody) =>
      importApi.createConnection(body),
    onSuccess: (res) => {
      if (res.success) {
        setSavedId(res.data.id);
        queryClient.invalidateQueries({ queryKey: ["import-connections"] });
        setStep(3);
      } else {
        setError(res.error.message);
      }
    },
  });

  const testMutation = useMutation({
    mutationFn: (id: string) => importApi.testConnection(id),
    onSuccess: (res) => {
      if (res.success) {
        setTestResult("Connection test passed.");
        queryClient.invalidateQueries({ queryKey: ["import-connections"] });
      } else {
        setTestResult(`Test failed: ${res.error.message}`);
      }
    },
  });

  const handleSave = () => {
    setError(null);
    if (!selectedTemplate) return;
    let config: Record<string, unknown> = {};
    let authConfig: Record<string, unknown> = {};
    try {
      config = JSON.parse(configJson);
      authConfig = JSON.parse(authConfigJson);
    } catch {
      setError("Invalid JSON in config fields");
      return;
    }
    saveMutation.mutate({
      name: name || `${selectedTemplate.name} Connection`,
      connection_type: selectedTemplate.slug,
      config,
      auth_type: authType,
      auth_config: authConfig,
      data_category_id: dataCategoryId || undefined,
    } as CreateConnectionBody);
  };

  return (
    <div>
      {/* Step indicator */}
      <div style={{ display: "flex", gap: "8px", marginBottom: "24px" }}>
        {[1, 2, 3].map((s) => (
          <div
            key={s}
            style={{
              flex: 1,
              height: "4px",
              borderRadius: "2px",
              background: s <= step ? "var(--io-accent)" : "var(--io-border)",
            }}
          />
        ))}
      </div>
      <div
        style={{
          fontSize: "11px",
          color: "var(--io-text-muted)",
          marginBottom: "20px",
          textTransform: "uppercase",
          letterSpacing: "0.05em",
        }}
      >
        Step {step} of 3 —{" "}
        {step === 1 ? "Select type" : step === 2 ? "Configure" : "Test & Save"}
      </div>

      {step === 1 && (
        <div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "8px",
              maxHeight: "360px",
              overflowY: "auto",
            }}
          >
            {templates.map((t) => (
              <button
                key={t.id}
                onClick={() => {
                  setSelectedTemplate(t);
                  setName(`${t.name} Connection`);
                }}
                style={{
                  background:
                    selectedTemplate?.id === t.id
                      ? "var(--io-accent-subtle)"
                      : "var(--io-surface-secondary)",
                  border: `1px solid ${selectedTemplate?.id === t.id ? "var(--io-accent)" : "var(--io-border)"}`,
                  borderRadius: "var(--io-radius)",
                  padding: "12px",
                  textAlign: "left",
                  cursor: "pointer",
                }}
              >
                <div
                  style={{
                    fontWeight: 600,
                    fontSize: "13px",
                    marginBottom: "2px",
                  }}
                >
                  {t.name}
                </div>
                <div
                  style={{ fontSize: "11px", color: "var(--io-text-muted)" }}
                >
                  {t.vendor} · {t.domain.replace(/_/g, " ")}
                </div>
              </button>
            ))}
          </div>
          <div
            style={{
              display: "flex",
              justifyContent: "flex-end",
              marginTop: "20px",
              gap: "8px",
            }}
          >
            <button onClick={onClose} style={secondaryBtnStyle}>
              Cancel
            </button>
            <button
              onClick={() => setStep(2)}
              disabled={!selectedTemplate}
              style={primaryBtnStyle}
            >
              Next
            </button>
          </div>
        </div>
      )}

      {step === 2 && selectedTemplate && (
        <div>
          <Field label="Connection Name">
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              style={inputStyle}
            />
          </Field>

          <Field label="Data Category">
            <select
              value={dataCategoryId}
              onChange={(e) => setDataCategoryId(e.target.value)}
              style={inputStyle}
            >
              <option value="">(none)</option>
              {categories.map((cat) => (
                <option key={cat.id} value={cat.id}>
                  {cat.label}
                </option>
              ))}
            </select>
          </Field>

          <Field label="Auth Type">
            <select
              value={authType}
              onChange={(e) => setAuthType(e.target.value)}
              style={inputStyle}
            >
              <option value="none">None</option>
              <option value="basic">Basic Auth</option>
              <option value="bearer">Bearer Token</option>
              <option value="api_key">API Key</option>
              <option value="oauth2">OAuth 2.0</option>
            </select>
          </Field>

          <Field label="Connection Config (JSON)">
            <textarea
              value={configJson}
              onChange={(e) => setConfigJson(e.target.value)}
              rows={5}
              style={{
                ...inputStyle,
                fontFamily: "monospace",
                fontSize: "12px",
                resize: "vertical",
              }}
              placeholder="{}"
            />
          </Field>

          {authType !== "none" && (
            <Field label="Auth Config (JSON)">
              <textarea
                value={authConfigJson}
                onChange={(e) => setAuthConfigJson(e.target.value)}
                rows={4}
                style={{
                  ...inputStyle,
                  fontFamily: "monospace",
                  fontSize: "12px",
                  resize: "vertical",
                }}
                placeholder="{}"
              />
            </Field>
          )}

          {error && (
            <div
              style={{
                padding: "10px",
                background: "var(--io-danger-subtle)",
                color: "var(--io-danger)",
                borderRadius: "var(--io-radius)",
                fontSize: "13px",
                marginBottom: "12px",
              }}
            >
              {error}
            </div>
          )}

          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              marginTop: "20px",
            }}
          >
            <button onClick={() => setStep(1)} style={secondaryBtnStyle}>
              Back
            </button>
            <button
              onClick={handleSave}
              disabled={saveMutation.isPending || !name.trim()}
              style={primaryBtnStyle}
            >
              {saveMutation.isPending ? "Saving..." : "Save & Continue"}
            </button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div style={{ textAlign: "center" }}>
          <div
            style={{
              fontSize: "48px",
              marginBottom: "12px",
              color: "var(--io-success)",
            }}
          >
            ✓
          </div>
          <div
            style={{ fontWeight: 600, fontSize: "16px", marginBottom: "8px" }}
          >
            Connection saved!
          </div>
          <p
            style={{
              color: "var(--io-text-secondary)",
              fontSize: "13px",
              marginBottom: "24px",
            }}
          >
            You can test the connection to verify it works.
          </p>

          {testResult && (
            <div
              style={{
                padding: "10px 12px",
                background: testResult.includes("failed")
                  ? "var(--io-danger-subtle)"
                  : "var(--io-success-subtle)",
                color: testResult.includes("failed")
                  ? "var(--io-danger)"
                  : "var(--io-success)",
                borderRadius: "var(--io-radius)",
                fontSize: "13px",
                marginBottom: "16px",
              }}
            >
              {testResult}
            </div>
          )}

          <div
            style={{ display: "flex", gap: "8px", justifyContent: "center" }}
          >
            {savedId && (
              <button
                onClick={() => testMutation.mutate(savedId)}
                disabled={testMutation.isPending}
                style={secondaryBtnStyle}
              >
                {testMutation.isPending ? "Testing..." : "Test Connection"}
              </button>
            )}
            <button onClick={onClose} style={primaryBtnStyle}>
              Done
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function EditConnectionForm({
  conn,
  onClose,
}: {
  conn: ImportConnection;
  onClose: () => void;
}) {
  const queryClient = useQueryClient();
  const [name, setName] = useState(conn.name);
  const [authType, setAuthType] = useState(conn.auth_type);
  const [configJson, setConfigJson] = useState(
    JSON.stringify(conn.config, null, 2),
  );
  const [enabled, setEnabled] = useState(conn.enabled);
  const [error, setError] = useState<string | null>(null);

  const mutation = useMutation({
    mutationFn: () => {
      const config = JSON.parse(configJson);
      return importApi.updateConnection(conn.id, {
        name,
        auth_type: authType,
        config,
        enabled,
      });
    },
    onSuccess: (res) => {
      if (res.success) {
        queryClient.invalidateQueries({ queryKey: ["import-connections"] });
        onClose();
      } else {
        setError(res.error.message);
      }
    },
  });

  return (
    <div>
      <Field label="Name">
        <input
          type="text"
          value={name}
          onChange={(e) => setName(e.target.value)}
          style={inputStyle}
        />
      </Field>

      <Field label="Auth Type">
        <select
          value={authType}
          onChange={(e) => setAuthType(e.target.value)}
          style={inputStyle}
        >
          <option value="none">None</option>
          <option value="basic">Basic Auth</option>
          <option value="bearer">Bearer Token</option>
          <option value="api_key">API Key</option>
          <option value="oauth2">OAuth 2.0</option>
        </select>
      </Field>

      <Field label="Config (JSON)">
        <textarea
          value={configJson}
          onChange={(e) => setConfigJson(e.target.value)}
          rows={6}
          style={{
            ...inputStyle,
            fontFamily: "monospace",
            fontSize: "12px",
            resize: "vertical",
          }}
        />
      </Field>

      <Field label="Enabled">
        <label
          style={{
            display: "flex",
            alignItems: "center",
            gap: "8px",
            cursor: "pointer",
          }}
        >
          <input
            type="checkbox"
            checked={enabled}
            onChange={(e) => setEnabled(e.target.checked)}
          />
          <span style={{ fontSize: "13px" }}>Connection enabled</span>
        </label>
      </Field>

      {error && (
        <div
          style={{
            padding: "10px",
            background: "var(--io-danger-subtle)",
            color: "var(--io-danger)",
            borderRadius: "var(--io-radius)",
            fontSize: "13px",
            marginBottom: "12px",
          }}
        >
          {error}
        </div>
      )}

      <div
        style={{
          display: "flex",
          gap: "8px",
          justifyContent: "flex-end",
          marginTop: "20px",
        }}
      >
        <button onClick={onClose} style={secondaryBtnStyle}>
          Cancel
        </button>
        <button
          onClick={() => mutation.mutate()}
          disabled={mutation.isPending}
          style={primaryBtnStyle}
        >
          {mutation.isPending ? "Saving..." : "Save Changes"}
        </button>
      </div>
    </div>
  );
}

