49	function formatExpiry(iso: string): string {
50	  const diff = new Date(iso).getTime() - Date.now();
51	  if (diff <= 0) return "expired";
52	  const days = Math.floor(diff / 86400000);
53	  const hrs = Math.floor((diff % 86400000) / 3600000);
54	  if (days > 0) return `${days}d ${hrs}h`;
55	  const mins = Math.floor((diff % 3600000) / 60000);
56	  if (hrs > 0) return `${hrs}h ${mins}m`;
57	  return `${mins}m`;
58	}
