2885	function usePointDetailConfig() {
2886	  const qc = useQueryClient();
2887	  const query = useQuery<PointDetailConfig>({
2888	    queryKey: ["point-detail-config"],
2889	    queryFn: async () => {
2890	      try {
2891	        const res = await fetch("/api/settings/point-detail-config");
2892	        if (!res.ok) throw new Error("API unavailable");
2893	        const json = await res.json();
2894	        return json.data ?? json;
2895	      } catch {
2896	        return { sections: DEFAULT_SECTIONS };
2897	      }
2898	    },
2899	    staleTime: 30_000,
2900	    initialData: { sections: DEFAULT_SECTIONS },
2901	  });
2902	
2903	  const saveMutation = useMutation({
2904	    mutationFn: async (config: PointDetailConfig) => {
2905	      const res = await fetch("/api/settings/point-detail-config", {
2906	        method: "PUT",
2907	        headers: { "Content-Type": "application/json" },
2908	        body: JSON.stringify(config),
2909	      });
2910	      if (!res.ok) throw new Error(await res.text());
2911	      return res.json();
2912	    },
2913	    onSuccess: () => {
2914	      qc.invalidateQueries({ queryKey: ["point-detail-config"] });
2915	    },
2916	  });
2917	
2918	  return { query, saveMutation };
2919	}
