3596	function applyTransforms(value: string, transforms: LinkTransform[]): string {
3597	  let v = value;
3598	  for (const t of transforms) {
3599	    try {
3600	      switch (t.op) {
3601	        case "uppercase":
3602	          v = v.toUpperCase();
3603	          break;
3604	        case "lowercase":
3605	          v = v.toLowerCase();
3606	          break;
3607	        case "trim":
3608	          v = v.trim();
3609	          break;
3610	        case "remove_dashes":
3611	          v = v.replace(/-/g, "");
3612	          break;
3613	        case "remove_spaces":
3614	          v = v.replace(/ /g, "");
3615	          break;
3616	        case "remove_underscores":
3617	          v = v.replace(/_/g, "");
3618	          break;
3619	        case "leading_zeros": {
3620	          const len = parseInt(t.params?.length ?? "6", 10);
3621	          v = v.padStart(len, "0");
3622	          break;
3623	        }
3624	        case "strip_prefix": {
3625	          const p = t.params?.prefix ?? "";
3626	          if (v.startsWith(p)) v = v.slice(p.length);
3627	          break;
3628	        }
3629	        case "strip_suffix": {
3630	          const s = t.params?.suffix ?? "";
3631	          if (v.endsWith(s)) v = v.slice(0, -s.length);
3632	          break;
3633	        }
3634	        case "replace":
3635	          v = v.split(t.params?.from ?? "").join(t.params?.to ?? "");
3636	          break;
3637	        case "regex_extract": {
3638	          const m = v.match(new RegExp(t.params?.pattern ?? ""));
3639	          const g = parseInt(t.params?.group ?? "0", 10);
3640	          v = m ? (m[g] ?? "") : "";
3641	          break;
3642	        }
3643	        case "substring": {
3644	          const st = parseInt(t.params?.start ?? "0", 10);
3645	          const en =
3646	            t.params?.end !== undefined
3647	              ? parseInt(t.params.end, 10)
3648	              : undefined;
3649	          v = v.slice(st, en);
3650	          break;
3651	        }
3652	      }
3653	    } catch {
3654	      /* ignore invalid transforms in preview */
3655	    }
3656	  }
3657	  return v;
3658	}
