3660	function transformLabel(t: LinkTransform): string {
3661	  const def = TRANSFORM_OPS.find((o) => o.op === t.op);
3662	  if (!def) return t.op;
3663	  if (!def.hasParams) return def.label;
3664	  const paramStr = Object.entries(t.params ?? {})
3665	    .map(([k, v]) => `${k}="${v}"`)
3666	    .join(", ");
3667	  return paramStr ? `${def.label} (${paramStr})` : def.label;
3668	}
