          No Point Detail sections configured. Loading default sections...
        </div>
      )}

      {/* Edit modal */}
      {editingSection && (
        <SectionEditModal
          section={editingSection}
          definitions={definitions}
          onSave={handleSectionSave}
          onClose={() => setEditingSection(null)}
        />
      )}
    </div>
  );
}

