399	function HistoryTab({ pointId }: { pointId: string }) {
400	  const query = useQuery({
401	    queryKey: ["point-metadata-versions", pointId],
402	    queryFn: async () => {
403	      const result = await pointConfigApi.getMetadataVersions(pointId);
404	      if (!result.success) throw new Error(result.error.message);
405	      return result.data as PointMetadataVersion[];
406	    },
407	  });
408	
409	  if (query.isLoading) {
410	    return (
411	      <div
412	        style={{
413	          padding: "20px",
414	          textAlign: "center",
415	          color: "var(--io-text-muted)",
416	          fontSize: "13px",
417	        }}
418	      >
419	        Loading history...
420	      </div>
421	    );
422	  }
423	
424	  if (query.isError) {
425	    return (
426	      <ErrorBanner
427	        message={
428	          query.error instanceof Error
429	            ? query.error.message
430	            : "Failed to load history"
431	        }
432	      />
433	    );
434	  }
435	
436	  const versions = query.data ?? [];
437	
438	  if (versions.length === 0) {
439	    return (
440	      <div
441	        style={{
442	          padding: "32px",
443	          textAlign: "center",
444	          color: "var(--io-text-muted)",
445	          fontSize: "13px",
446	        }}
447	      >
448	        No version history recorded for this point.
449	      </div>
450	    );
451	  }
452	
453	  return (
454	    <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
455	      {versions.map((v) => (
456	        <div
457	          key={v.id}
458	          style={{
459	            background: "var(--io-surface-sunken)",
460	            border: "1px solid var(--io-border)",
461	            borderRadius: "6px",
462	            padding: "10px 14px",
463	          }}
464	        >
465	          <div
466	            style={{
467	              display: "flex",
468	              alignItems: "center",
469	              justifyContent: "space-between",
470	              marginBottom: "6px",
471	            }}
472	          >
473	            <span
474	              style={{
475	                fontSize: "11px",
476	                fontWeight: 700,
477	                color: "var(--io-text-muted)",
478	                textTransform: "uppercase",
479	                letterSpacing: "0.06em",
480	              }}
481	            >
482	              Version {v.version}
483	            </span>
484	            <span style={{ fontSize: "11px", color: "var(--io-text-muted)" }}>
485	              {new Date(v.changed_at).toLocaleString()}
486	              {v.changed_by ? ` · ${v.changed_by}` : ""}
487	            </span>
488	          </div>
489	          <div style={{ display: "flex", flexDirection: "column", gap: "3px" }}>
490	            {Object.entries(v.changes).map(([field, change]) => (
491	              <div
492	                key={field}
493	                style={{ fontSize: "12px", color: "var(--io-text-secondary)" }}
494	              >
495	                <span
496	                  style={{ fontWeight: 500, color: "var(--io-text-primary)" }}
497	                >
498	                  {field}
499	                </span>
500	                {": "}
501	                <span
502	                  style={{
503	                    color: "var(--io-danger)",
504	                    textDecoration: "line-through",
505	                    marginRight: "4px",
506	                  }}
507	                >
508	                  {change.old == null ? "null" : String(change.old)}
509	                </span>
510	                <span style={{ color: "var(--io-success)" }}>
511	                  {change.new == null ? "null" : String(change.new)}
512	                </span>
513	              </div>
514	            ))}
515	          </div>
516	        </div>
517	      ))}
518	    </div>
519	  );
