  borderBottom: "1px solid var(--io-border)",
  color: "var(--io-text-muted)",
  fontWeight: 600,
  background: "var(--io-surface-sunken)",
};

const TD: React.CSSProperties = {
  padding: "6px 10px",
  borderBottom: "1px solid var(--io-border)",
  color: "var(--io-text-primary)",
  verticalAlign: "top" as const,
};

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function fmtDate(iso: string) {
  try {
    return new Date(iso).toLocaleString();
  } catch {
    return iso;
  }
}

function Badge({
  children,
  color,
}: {
  children: React.ReactNode;
  color: "success" | "warning" | "danger" | "accent" | "muted";
}) {
  const colors = {
    success: { bg: "var(--io-success-subtle)", fg: "var(--io-success)" },
    warning: { bg: "var(--io-warning-subtle)", fg: "var(--io-warning)" },
    danger: { bg: "var(--io-danger-subtle)", fg: "var(--io-danger)" },
    accent: { bg: "var(--io-accent-subtle)", fg: "var(--io-accent)" },
    muted: { bg: "var(--io-surface-sunken)", fg: "var(--io-text-muted)" },
  };
  const c = colors[color];
  return (
    <span
      style={{
        display: "inline-block",
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "11px",
        fontWeight: 600,
        background: c.bg,
        color: c.fg,
      }}
    >
      {children}
    </span>
  );
}

function SectionTitle({ children }: { children: React.ReactNode }) {
  return (
    <h3
      style={{
        margin: "0 0 var(--io-space-3)",
        fontSize: "13px",
        fontWeight: 600,
        color: "var(--io-text-secondary)",
        textTransform: "uppercase",
        letterSpacing: "0.05em",
      }}
    >
      {children}
    </h3>
  );
}

// ---------------------------------------------------------------------------
// Tab: Bulk Update
// ---------------------------------------------------------------------------

function DiffSection({
  title,
  color,
  rows,
}: {
  title: string;
  color: "success" | "warning" | "danger";
  rows: Record<string, unknown>[];
}) {
  if (rows.length === 0) return null;
  const keys = Object.keys(rows[0]);
  return (
    <div style={{ marginBottom: "var(--io-space-4)" }}>
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "var(--io-space-2)",
          marginBottom: "var(--io-space-2)",
        }}
      >
        <Badge color={color}>{title}</Badge>
        <span style={{ color: "var(--io-text-muted)", fontSize: "12px" }}>
          {rows.length} row{rows.length !== 1 ? "s" : ""}
        </span>
      </div>
      <div style={{ overflowX: "auto" }}>
        <table style={TABLE}>
          <thead>
            <tr>
              {keys.map((k) => (
                <th key={k} style={TH}>
                  {k}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {rows.map((row, i) => (
              <tr key={i}>
                {keys.map((k) => (
                  <td key={k} style={TD}>
                    {String(row[k] ?? "")}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function ModifiedSection({ rows }: { rows: ModifiedRow[] }) {
  if (rows.length === 0) return null;
  return (
    <div style={{ marginBottom: "var(--io-space-4)" }}>
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "var(--io-space-2)",
          marginBottom: "var(--io-space-2)",
        }}
      >
        <Badge color="warning">Modified</Badge>
        <span style={{ color: "var(--io-text-muted)", fontSize: "12px" }}>
          {rows.length} row{rows.length !== 1 ? "s" : ""}
        </span>
      </div>
      <div style={{ overflowX: "auto" }}>
        <table style={TABLE}>
          <thead>
            <tr>
              <th style={TH}>ID</th>
              <th style={TH}>Changed Fields</th>
              <th style={TH}>Before</th>
              <th style={TH}>After</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((row) => (
              <tr key={row.id}>
                <td
                  style={{ ...TD, fontFamily: "monospace", fontSize: "11px" }}
                >
                  {row.id}
                </td>
                <td style={TD}>
                  {row.changed_fields.map((f) => (
                    <Badge key={f} color="accent">
                      {f}
                    </Badge>
                  ))}
                </td>
                <td
                  style={{
                    ...TD,
                    fontFamily: "monospace",
                    fontSize: "11px",
                    color: "var(--io-danger)",
                  }}
                >
                  {row.changed_fields.map((f) => (
                    <div key={f}>
                      {f}: {String(row.before[f] ?? "")}
                    </div>
                  ))}
                </td>
                <td
                  style={{
                    ...TD,
                    fontFamily: "monospace",
                    fontSize: "11px",
                    color: "var(--io-success)",
                  }}
                >
                  {row.changed_fields.map((f) => (
                    <div key={f}>
                      {f}: {String(row.after[f] ?? "")}
                    </div>
                  ))}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function ConflictedSection({
  rows,
  resolution,
