  return (
    <div
      style={{
        marginBottom: "var(--io-space-4)",
        border: "1px solid var(--io-warning)",
        borderRadius: "6px",
        padding: "var(--io-space-3)",
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "var(--io-space-2)",
          marginBottom: "var(--io-space-3)",
