      {totalErrors > 0 && (
        <>
          <div
            style={{
              overflowX: "auto",
              maxHeight: 200,
              marginBottom: "var(--io-space-3)",
            }}
          >
            <table style={TABLE}>
              <thead>
                <tr>
                  <th style={TH}>Row</th>
                  <th style={TH}>ID</th>
                  <th style={TH}>Field</th>
                  <th style={TH}>Error</th>
                </tr>
              </thead>
              <tbody>
                {validation.errors.slice(0, 50).map((err, i) => (
                  <tr key={i}>
                    <td style={TD}>{err.row}</td>
                    <td
                      style={{
                        ...TD,
                        fontFamily: "monospace",
                        fontSize: "11px",
                      }}
                    >
                      {err.id || "—"}
                    </td>
                    <td
                      style={{
                        ...TD,
                        fontFamily: "monospace",
                        fontSize: "11px",
                      }}
                    >
                      {err.field ?? "—"}
                    </td>
                    <td
                      style={{
                        ...TD,
                        color: "var(--io-danger)",
                        fontSize: "12px",
                      }}
                    >
                      {err.error}
                    </td>
                  </tr>
                ))}
                {validation.errors.length > 50 && (
                  <tr>
                    <td
                      colSpan={4}
                      style={{
                        ...TD,
                        color: "var(--io-text-muted)",
                        fontStyle: "italic",
                      }}
                    >
                      … and {validation.errors.length - 50} more errors
